package main

import (
    "log"
    "os"
    "sync"
)

type Logger struct {
    file *os.File
    mu   sync.Mutex
}

func NewLogger(filename string) (*Logger, error) {
    file, err := os.OpenFile(filename, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
    if err != nil {
        return nil, err
    }
    return &Logger{file: file}, nil
}

func (l *Logger) Log(msg string) {
    l.mu.Lock()
    defer l.mu.Unlock()
    log.SetOutput(l.file)
    log.Println(msg)
}

func (l *Logger) Close() error {
    return l.file.Close()
}

func main() {
    logger, err := NewLogger("app.log")
    if err != nil {
        log.Fatal(err)
    }
    defer logger.Close()

    for i := 0; i < 1000; i++ {
        logger.Log("Log entry " + string(i))
    }
}

import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ExecutionException;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

public class AsyncTaskOrchestrator {
    private ExecutorService executor = Executors.newFixedThreadPool(2);

    public void processTasks() {
        CompletableFuture<String> task1 = CompletableFuture.supplyAsync(() -> {
            // 模拟异步任务1：从数据库获取数据
            if (Math.random() < 0.1) {
                throw new RuntimeException("Database connection failed");
            }
            return "Data from task1";
        }, executor);

        CompletableFuture<String> task2 = CompletableFuture.supplyAsync(() -> {
            // 模拟异步任务2：调用外部API
            if (Math.random() < 0.05) {
                throw new RuntimeException("API timeout");
            }
            return "Data from task2";
        }, executor);

        CompletableFuture<Void> combinedTask = task1.thenCombine(task2, (result1, result2) -> {
            // 组合两个任务的结果
            System.out.println("Combined result: " + result1 + " and " + result2);
            return null;
        });

        try {
            combinedTask.get(); // 等待组合任务完成
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            System.err.println("Task interrupted: " + e.getMessage());
        } catch (ExecutionException e) {
            System.err.println("Execution error: " + e.getMessage());
        }
    }

    public void shutdown() {
        executor.shutdown();
    }
}

