const fs = require('fs');
const path = require('path');

class MemoryMappedFileHandler {
    constructor(filePath) {
        this.filePath = filePath;
        this.fileDescriptor = null;
        this.mappedBuffer = null;
    }

    openAndMap() {
        try {
            this.fileDescriptor = fs.openSync(this.filePath, 'r+');
            const stats = fs.fstatSync(this.fileDescriptor);
            const fileSize = stats.size;
            this.mappedBuffer = Buffer.alloc(fileSize);
            fs.readSync(this.fileDescriptor, this.mappedBuffer, 0, fileSize, 0);
            console.log('File mapped successfully, size:', fileSize);
        } catch (error) {
            console.error('Error mapping file:', error);
        }
    }

    readData(offset, length) {
        if (!this.mappedBuffer) {
            throw new Error('File not mapped');
        }
        if (offset + length > this.mappedBuffer.length) {
            throw new Error('Read out of bounds');
        }
        return this.mappedBuffer.slice(offset, offset + length);
    }

    writeData(offset, data) {
        if (!this.mappedBuffer) {
            throw new Error('File not mapped');
        }
        if (offset + data.length > this.mappedBuffer.length) {
            throw new Error('Write out of bounds');
        }
        data.copy(this.mappedBuffer, offset);
        fs.writeSync(this.fileDescriptor, this.mappedBuffer, 0, this.mappedBuffer.length, 0);
    }

    close() {
        if (this.fileDescriptor) {
            fs.closeSync(this.fileDescriptor);
            this.fileDescriptor = null;
        }
        this.mappedBuffer = null;
    }
}

// Usage example
const handler = new MemoryMappedFileHandler('data.bin');
handler.openAndMap();
const data = handler.readData(0, 10);
console.log('Read data:', data);
handler.writeData(10, Buffer.from('new data'));
handler.close();

