use std::fs::File;
use std::io::{self, Read, Write};
use std::path::Path;
use image::{DynamicImage, ImageFormat};
use image::codecs::jpeg::JpegEncoder;
use std::sync::Arc;
use std::thread;

pub struct ImageCompressor {
    quality: u8,
}

impl ImageCompressor {
    pub fn new(quality: u8) -> Self {
        ImageCompressor { quality }
    }

    pub fn compress_image(&self, input_path: &str, output_path: &str) -> Result<(), String> {
        let path = Path::new(input_path);
        if !path.exists() {
            return Err("Input file does not exist".to_string());
        }

        let mut file = match File::open(path) {
            Ok(f) => f,
            Err(_) => return Err("Failed to open input file".to_string()),
        };

        let mut buffer = Vec::new();
        if let Err(_) = file.read_to_end(&mut buffer) {
            return Err("Failed to read input file".to_string());
        }

        let img = match image::load_from_memory(&buffer) {
            Ok(i) => i,
            Err(_) => return Err("Failed to decode image".to_string()), 
        };

        let compressed = self.resize_and_compress(img);

        let output_path_obj = Path::new(output_path);
        let mut output_file = match File::create(output_path_obj) {
            Ok(f) => f,
            Err(_) => return Err("Failed to create output file".to_string()),
        };

        let mut encoder = JpegEncoder::new_with_quality(&mut output_file, self.quality);
        match compressed.write_with_encoder(&mut encoder) {
            Ok(_) => Ok(()),
            Err(_) => Err("Failed to write compressed image".to_string()),
        }
    }

    fn resize_and_compress(&self, img: DynamicImage) -> DynamicImage {
        let (width, height) = img.dimensions();
        let new_width = (width as f32 * 0.5) as u32;
        let new_height = (height as f32 * 0.5) as u32;
        img.resize(new_width, new_height, image::imageops::FilterType::Lanczos3)
    }

    pub fn batch_compress(&self, paths: Vec<(String, String)>) -> Vec<Result<(), String>> {
        let self_arc = Arc::new(self);
        let mut handles = vec![];

        for (input, output) in paths {
            let compressor = Arc::clone(&self_arc);
            let handle = thread::spawn(move || {
                compressor.compress_image(&input, &output)
            });
            handles.push(handle);
        }

        handles.into_iter().map(|h| h.join().unwrap()).collect()
    }
}

