use std::fs::File;
use std::io::{self, Read, Write};
use zip::write::SimpleFileOptions;
use zip::ZipWriter;
use zip::read::ZipArchive;
use std::path::Path;

fn compress_files(file_paths: &[&str], output_path: &str) -> io::Result<()> {
    let file = File::create(output_path)?;
    let mut zip = ZipWriter::new(file);
    for path in file_paths {
        let mut file = File::open(path)?;
        let mut buffer = Vec::new();
        file.read_to_end(&mut buffer)?;
        zip.start_file(path, SimpleFileOptions::default())?;
        zip.write_all(&buffer)?;
    }
    zip.finish()?;
    Ok(())
}

fn extract_zip(zip_path: &str, output_dir: &str) -> io::Result<()> {
    let file = File::open(zip_path)?;
    let mut archive = ZipArchive::new(file)?;
    for i in 0..archive.len() {
        let mut file = archive.by_index(i)?;
        let outpath = Path::new(output_dir).join(file.name());
        let mut outfile = File::create(&outpath)?;
        io::copy(&mut file, &mut outfile)?;
    }
    Ok(())
}

fn main() {
    let files = ["data1.txt", "data2.txt"];
    if let Err(e) = compress_files(&files, "archive.zip") {
        eprintln!("压缩失败: {}", e);
    }
    if let Err(e) = extract_zip("archive.zip", "extracted") {
        eprintln!("解压失败: {}", e);
    }
}

