                generatePdf(content, filename);
            } catch (Exception e) {
                System.err.println("Error generating PDF: " + e.getMessage());
            }
        });
    }

    private void generatePdf(String content, String filename) throws IOException {
        if (content == null || content.trim().isEmpty()) {
