            throw new IllegalArgumentException("Filename must end with .pdf");
        }
        String fullPath = outputPath + filename;
        try (FileOutputStream fos = new FileOutputStream(fullPath)) {
            byte[] pdfData = simulatePdfGeneration(content);
            fos.write(pdfData);
        } catch (IOException e) {
            throw new IOException("Failed to write PDF file: " + e.getMessage(), e);
        }
    }

    private byte[] simulatePdfGeneration(String content) {
        // Simulate PDF generation logic
        if (content.length() > 10000) {
            throw new RuntimeException("Content too large for PDF generation");
        }
        return content.getBytes();
    }

    public void shutdown() {
        executor.shutdown();
    }
}

