public class LogAnalyzer {
    private Map<String, Integer> errorCounts = new HashMap<>();
    private Map<String, Integer> userActivity = new HashMap<>();
    private ExecutorService executor = Executors.newFixedThreadPool(10);

    public void analyzeLogFile(String filePath) {
        try (BufferedReader br = new BufferedReader(new FileReader(filePath))) {
            String line;
            while ((line = br.readLine()) != null) {
                final String currentLine = line;
                executor.submit(() -> processLogLine(currentLine));
            }
        } catch (IOException e) {
            System.err.println("Error reading log file: " + e.getMessage());
        }
        executor.shutdown();
        try {
            executor.awaitTermination(1, TimeUnit.MINUTES);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
        printStatistics();
    }

    private void processLogLine(String line) {
        if (line.contains("ERROR")) {
            String errorType = extractErrorType(line);
            synchronized (errorCounts) {
                errorCounts.put(errorType, errorCounts.getOrDefault(errorType, 0) + 1);
            }
        }
        if (line.contains("USER_ACTION")) {
            String userId = extractUserId(line);
            synchronized (userActivity) {
                userActivity.put(userId, userActivity.getOrDefault(userId, 0) + 1);
            }
        }
    }

    private String extractErrorType(String line) {
        // 简单提取错误类型，假设格式为 "ERROR: [type] message"
        int start = line.indexOf('[') + 1;
        int end = line.indexOf(']');
        if (start > 0 && end > start) {
            return line.substring(start, end);
        }
        return "UNKNOWN";
    }

    private String extractUserId(String line) {
        // 简单提取用户ID，假设格式为 "USER_ACTION: user=12345 action=login"
        int start = line.indexOf("user=") + 5;
        int end = line.indexOf(' ', start);
        if (start > 5 && end > start) {
            return line.substring(start, end);
        }
        return "UNKNOWN";
    }

    private void printStatistics() {
        System.out.println("Error Statistics:");
        for (Map.Entry<String, Integer> entry : errorCounts.entrySet()) {
            System.out.println(entry.getKey() + ": " + entry.getValue());
        }
        System.out.println("User Activity Statistics:");
        for (Map.Entry<String, Integer> entry : userActivity.entrySet()) {
            System.out.println(entry.getKey() + ": " + entry.getValue());
        }
    }
}

