                data = json.load(f)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON in config file: {e}")
        except IOError as e:
            raise IOError(f"Error reading config file: {e}")

        # Basic validation: ensure required keys exist
        required_keys = {"api_key", "timeout", "retry_count"}
        if not required_keys.issubset(data.keys()):
            missing = required_keys - data.keys()
            raise ValueError(f"Missing required config keys: {missing}")

        # Type validation for key values
        if not isinstance(data.get("api_key"), str) or not data["api_key"]:
            raise ValueError("api_key must be a non-empty string")
        if not isinstance(data.get("timeout"), (int, float)) or data["timeout"] <= 0:
