class UserInfoProcessor {
  constructor() {
    this.users = new Map(); // 使用 Map 提高查找效率
  }

  addUser(id, name, email) {
    if (!id || !name || !email) {
      throw new Error('Invalid input: id, name, and email are required');
    }
    if (this.users.has(id)) {
      throw new Error(`User with id ${id} already exists`);
    }
    if (!this.validateEmail(email)) {
      throw new Error(`Invalid email format for user ${id}`);
    }
    this.users.set(id, { name, email });
  }

  updateUser(id, updates) {
    if (!this.users.has(id)) {
      throw new Error(`User with id ${id} not found`);
    }
    const user = this.users.get(id);
    this.users.set(id, { ...user, ...updates });
  }

  deleteUser(id) {
    if (!this.users.has(id)) {
      throw new Error(`User with id ${id} not found`);
    }
    this.users.delete(id);
  }

  getUser(id) {
    return this.users.get(id);
  }

  getAllUsers() {
    return Array.from(this.users.values());
  }

  validateEmail(email) {
    // 使用更健壮的正则表达式或库如 validator.js
    const regex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return regex.test(email);
  }

  async processBatch(userDataArray) {
    const promises = userDataArray.map(async data => {
      try {
        this.addUser(data.id, data.name, data.email);
      } catch (error) {
        console.error(`Failed to add user ${data.id}:`, error.message);
      }
    });
    await Promise.all(promises); // 处理并发，确保顺序无关
  }

  findUsersByName(name) {
    // 可考虑添加索引如 Map<name, id[]> 以提高性能
    return Array.from(this.users.values()).filter(user => user.name === name);
  }

  clearAllUsers() {
    this.users.clear();
  }
}
