import pika
import json
import time
from typing import Optional

class MessageQueueProducer:
    def __init__(self, host: str = 'localhost', queue_name: str = 'task_queue'):
        self.host = host
        self.queue_name = queue_name
        self.connection: Optional[pika.BlockingConnection] = None
        self.channel: Optional[pika.adapters.blocking_connection.BlockingChannel] = None
        self._connect()

    def _connect(self) -> None:
        """Establish connection to RabbitMQ."""
        try:
            self.connection = pika.BlockingConnection(pika.ConnectionParameters(host=self.host))
            self.channel = self.connection.channel()
            self.channel.queue_declare(queue=self.queue_name, durable=True)
            print(f"Connected to {self.host} on queue {self.queue_name}")
        except Exception as e:
            print(f"Connection failed: {e}")
            self.connection = None
            self.channel = None

    def send_message(self, message: dict) -> bool:
        """Send a message to the queue."""
        if not self.channel:
            self._connect()
            if not self.channel:
                return False
        try:
            self.channel.basic_publish(
                exchange='',
                routing_key=self.queue_name,
                body=json.dumps(message),
                properties=pika.BasicProperties(
                    delivery_mode=2,  # make message persistent
                )
            )
            print(f"Sent: {message}")
            return True
        except Exception as e:
            print(f"Send failed: {e}")
            return False

    def close(self) -> None:
        """Close the connection."""
        if self.connection and not self.connection.is_closed:
            self.connection.close()
            print("Connection closed")

    def __del__(self) -> None:
        """Destructor to ensure cleanup."""
        self.close()

# Example usage
if __name__ == "__main__":
    producer = MessageQueueProducer(host='localhost', queue_name='order_processing')
    for i in range(10):
        message = {"order_id": i, "status": "pending", "timestamp": time.time()}
        producer.send_message(message)
        time.sleep(0.1)
    producer.close()

