import fs from 'fs';
import path from 'path';

class LogRotator {
  private logDir: string;
  private maxSize: number;
  private currentFile: string;

  constructor(logDir: string, maxSize: number = 1024 * 1024) {
    this.logDir = logDir;
    this.maxSize = maxSize;
    this.currentFile = path.join(logDir, 'app.log');
    if (!fs.existsSync(logDir)) {
      fs.mkdirSync(logDir, { recursive: true });
    }
  }

  public log(message: string): void {
    try {
      const stats = fs.statSync(this.currentFile);
      if (stats.size > this.maxSize) {
        this.rotateLog();
      }
      fs.appendFileSync(this.currentFile, message + '\n');
    } catch (error) {
      console.error('Error logging:', error);
    }
  }

  private rotateLog(): void {
    const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
    const newFile = path.join(this.logDir, `app-${timestamp}.log`);
    fs.renameSync(this.currentFile, newFile);
    this.currentFile = path.join(this.logDir, 'app.log');
  }
}

