import requests
import time
from concurrent.futures import ThreadPoolExecutor
from typing import Optional, Dict

class ServiceHealthChecker:
    def __init__(self, service_urls: Dict[str, str], timeout: int = 5):
        self.service_urls = service_urls
        self.timeout = timeout
        self.results = {}

    def check_single_service(self, service_name: str, url: str) -> bool:
        try:
            response = requests.get(url, timeout=self.timeout)
            if response.status_code == 200:
                return True
            else:
                return False
        except requests.exceptions.RequestException:
            return False

    def run_checks(self) -> Dict[str, bool]:
        with ThreadPoolExecutor(max_workers=len(self.service_urls)) as executor:
            futures = {}
            for service_name, url in self.service_urls.items():
                future = executor.submit(self.check_single_service, service_name, url)
                futures[future] = service_name

            for future in futures:
                service_name = futures[future]
                try:
                    result = future.result(timeout=self.timeout + 2)
                    self.results[service_name] = result
                except Exception as e:
                    self.results[service_name] = False

        return self.results

    def generate_report(self) -> str:
        healthy_count = sum(1 for result in self.results.values() if result)
        total_count = len(self.results)
        report = f"Health Check Report:\n"
        report += f"Healthy Services: {healthy_count}/{total_count}\n"
        for service_name, is_healthy in self.results.items():
            status = "Healthy" if is_healthy else "Unhealthy"
            report += f"  - {service_name}: {status}\n"
        return report

# Example usage
