fn process_user_input(input_str: &str) -> String {
    const MAX_LENGTH: usize = 50;
    let mut result = String::with_capacity(input_str.len().min(MAX_LENGTH));

    for c in input_str.chars() {
        match c {
            c if c.is_ascii_alphabetic() => result.push(c.to_ascii_uppercase()),
            c if c.is_ascii_digit() => result.push(c),
