const amqp = require('amqplib');

class MessageQueueProducer {
    constructor(queueName, connectionUrl = 'amqp://localhost') {
        this.queueName = queueName;
        this.connectionUrl = connectionUrl;
        this.connection = null;
        this.channel = null;
        this.isConnected = false;
    }

    async connect() {
        try {
            this.connection = await amqp.connect(this.connectionUrl);
            this.channel = await this.connection.createChannel();
            await this.channel.assertQueue(this.queueName, { durable: true });
            this.isConnected = true;
            console.log('Connected to RabbitMQ');
        } catch (error) {
            console.error('Connection failed:', error);
            this.isConnected = false;
            throw new Error('Failed to connect to message queue');
        }
    }

    async sendMessage(message, maxRetries = 3) {
        if (!this.isConnected) {
            await this.connect();
        }
        let retries = 0;
        while (retries < maxRetries) {
            try {
                const sent = this.channel.sendToQueue(this.queueName, Buffer.from(message));
                if (sent) {
                    console.log(`Sent: ${message}`);
                    return;
                } else {
                    throw new Error('Message send failed');
                }
            } catch (error) {
                retries++;
                console.warn(`Send attempt ${retries} failed:`, error);
                if (retries >= maxRetries) {
                    throw new Error('Max retries exceeded for message send');
                }
                await new Promise(resolve => setTimeout(resolve, 1000)); // 等待1秒后重试
            }
        }
    }

    async close() {
        if (this.channel && this.isConnected) {
            await this.channel.close();
            this.channel = null;
        }
        if (this.connection && this.isConnected) {
            await this.connection.close();
            this.connection = null;
            this.isConnected = false;
        }
    }
}

// 使用示例
const producer = new MessageQueueProducer('orderQueue', process.env.RABBITMQ_URL || 'amqp://localhost');
(async () => {
    try {
        await producer.sendMessage('Order placed: #12345');
    } catch (error) {
        console.error('Error sending message:', error);
    } finally {
        await producer.close();
    }
})();
```

### 最佳实践
