import threading
import time

class DataProcessor:
    def __init__(self, data_source):
        self.data_source = data_source
        self.lock = threading.Lock()
        self.cache = {}
        self.processed_count = 0

    def process_data(self, key):
        # 获取锁以访问共享资源
        self.lock.acquire()
        try:
            if key in self.cache:
                result = self.cache[key]
            else:
                # 模拟从数据源获取数据
                time.sleep(0.1)  # 模拟I/O延迟
                result = self.data_source.get(key)
                self.cache[key] = result
            self.processed_count += 1
            # 处理数据
            processed_result = self._transform(result)
            return processed_result
        finally:
            self.lock.release()

    def _transform(self, data):
        # 简单的数据转换逻辑
        if isinstance(data, str):
            return data.upper()
        elif isinstance(data, int):
            return data * 2
        else:
            return None

    def get_stats(self):
        self.lock.acquire()
        try:
            return {
                'processed': self.processed_count,
                'cached_keys': len(self.cache)
            }
        finally:
            self.lock.release()

    def clear_cache(self):
        self.lock.acquire()
        self.cache.clear()
        self.processed_count = 0
        self.lock.release()

# 示例使用
