        for index, row in self.data.iterrows():
            region = row['region']
            sales = row['sales']
            if region in aggregated:
                aggregated[region] += sales
            else:
                aggregated[region] = sales
        return aggregated

    def calculate_average_sales(self):
        # 计算每个区域的平均销售额
        aggregated = self.aggregate_sales_by_region()
        region_counts = {}
        for index, row in self.data.iterrows():
            region = row['region']
            if region in region_counts:
                region_counts[region] += 1
            else:
                region_counts[region] = 1
        averages = {}
        for region, total_sales in aggregated.items():
            averages[region] = total_sales / region_counts[region]
        return averages

    def top_regions(self, n=5):
        # 找出销售额最高的前n个区域
        aggregated = self.aggregate_sales_by_region()
        sorted_regions = sorted(aggregated.items(), key=lambda x: x[1], reverse=True)
        return sorted_regions[:n]

