func healthCheck(url string) bool {
    client := &http.Client{}
    resp, err := client.Get(url)
    if err != nil {
        fmt.Printf("Error checking %s: %v\n", url, err)
        return false
    }
    defer resp.Body.Close()
    if resp.StatusCode != http.StatusOK {
        fmt.Printf("Health check failed for %s: status %d\n", url, resp.StatusCode)
        return false
    }
    return true
}

func checkAllServices(services []string) []bool {
    var wg sync.WaitGroup
    results := make([]bool, len(services))
    for i, service := range services {
        wg.Add(1)
        go func(i int, service string) {
            defer wg.Done()
            results[i] = healthCheck(service)
        }(i, service)
    }
    wg.Wait()
    return results
}

func main() {
    services := []string{"http://api.example.com/health", "http://db.example.com/health", "http://cache.example.com/health"}
    start := time.Now()
    results := checkAllServices(services)
    elapsed := time.Since(start)
    fmt.Printf("Health check results: %v\n", results)
    fmt.Printf("Time taken: %v\n", elapsed)
}

