class Logger {
  private logFilePath: string;

  constructor(logDir: string) {
    this.logFilePath = path.join(logDir, 'app.log');
    if (!fs.existsSync(logDir)) {
      fs.mkdirSync(logDir, { recursive: true });
    }
  }

  public log(message: string, level: string = 'INFO', userInput: string = ''): void {
    const timestamp = new Date().toISOString();
    const logEntry = `${timestamp} [${level}] ${message} ${userInput}\n`;

    fs.appendFile(this.logFilePath, logEntry, (err) => {
      if (err) {
        console.error('Failed to write log:', err);
      }
    });
  }

  public readLogs(): string {
    if (fs.existsSync(this.logFilePath)) {
      return fs.readFileSync(this.logFilePath, 'utf8');
    }
    return '';
  }

  public clearLogs(): void {
    if (fs.existsSync(this.logFilePath)) {
      fs.unlinkSync(this.logFilePath);
    }
  }
}

