CREATE OR REPLACE FUNCTION get_database_connection() RETURNS connection AS $$
DECLARE
    conn connection;
    instance_created BOOLEAN := FALSE;
BEGIN
    IF instance_created = FALSE THEN
        conn := dblink_connect('host=localhost dbname=mydb user=myuser password=mypass');
        instance_created := TRUE;
    END IF;
    RETURN conn;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION initialize_singleton() RETURNS VOID AS $$
DECLARE
    conn connection;
BEGIN
    conn := get_database_connection();
    IF conn IS NULL THEN
        RAISE EXCEPTION 'Connection failed';
    END IF;
    PERFORM dblink_exec(conn, 'CREATE TABLE IF NOT EXISTS singleton_data (id SERIAL PRIMARY KEY, value TEXT)');
    PERFORM dblink_exec(conn, 'INSERT INTO singleton_data (value) VALUES (''initialized'')');
    PERFORM dblink_disconnect(conn);
END;
$$ LANGUAGE plpgsql;

