package main

import (
    "fmt"
    "io"
    "os"
    "sync"
    "time"
)

type Logger struct {
    file   *os.File
    mu     sync.Mutex
    buffer []byte
}

func NewLogger(filename string) (*Logger, error) {
    file, err := os.OpenFile(filename, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
    if err != nil {
        return nil, err
    }
    return &Logger{file: file, buffer: make([]byte, 0, 1024)}, nil
}

func (l *Logger) WriteLog(level, message string) {
    l.mu.Lock()
    defer l.mu.Unlock()
    timestamp := time.Now().Format("2006-01-02 15:04:05")
    logEntry := fmt.Sprintf("%s [%s] %s\n", timestamp, level, message)
    l.buffer = append(l.buffer, logEntry...)
    if len(l.buffer) >= 512 {
        _, err := l.file.Write(l.buffer)
        if err != nil {
            fmt.Printf("Failed to write log: %v\n", err)
        }
        l.buffer = l.buffer[:0]
    }
}

func (l *Logger) Flush() {
    l.mu.Lock()
    defer l.mu.Unlock()
    if len(l.buffer) > 0 {
        _, err := l.file.Write(l.buffer)
        if err != nil {
            fmt.Printf("Failed to flush log: %v\n", err)
        }
        l.buffer = l.buffer[:0]
    }
}

func (l *Logger) Close() error {
    l.Flush()
    return l.file.Close()
}

func main() {
    logger, err := NewLogger("/var/log/app.log")
    if err != nil {
        panic(err)
    }
    defer logger.Close()
    logger.WriteLog("INFO", "Application started")
    logger.WriteLog("ERROR", "Something went wrong")
}

