    except requests.exceptions.Timeout:
        return {"error": "请求超时"}
    except requests.exceptions.HTTPError as e:
        return {"error": f"HTTP错误: {e}"}
    except json.JSONDecodeError:
        return {"error": "JSON解析失败"}
    except Exception as e:
        return {"error": f"未知错误: {e}"}

