        } else {
            return res.status(400).json({ error: 'Unsupported currency' });
        }
    }

    if (!userBalances[userId]) {
        userBalances[userId] = 1000; // Default balance for new users
    }

    if (finalAmount > userBalances[userId]) {
        return res.status(400).json({ error: 'Insufficient balance' });
    }

    userBalances[userId] -= finalAmount;

    transactionLog.push({
