// Resolve the API base with a bias toward same-origin requests when the app is
// running on localhost/private development hosts. This avoids production API
// CORS/CSRF origin checks rejecting requests from a local Node/Vite session
// that was built with a production `VITE_API_BASE`.
function normalizeBase(value) {
  return String(value || '').trim().replace(/\/$/, '');
}

function isLocalHostname(hostname) {
  const host = String(hostname || '').trim().toLowerCase();
  return (
    host === 'localhost' ||
    host === '127.0.0.1' ||
    host === '0.0.0.0' ||
    host === '[::1]'
  );
}

function resolveApiBase() {
  const configuredBase = normalizeBase(import.meta.env.VITE_API_BASE || '/api');
  if (typeof window === 'undefined' || !window.location) {
    return configuredBase || '/api';
  }

  const currentOrigin = normalizeBase(window.location.origin);
  const currentHostname = window.location.hostname;

  if (!configuredBase || configuredBase.startsWith('/')) {
    return configuredBase || '/api';
  }

  try {
