function isLocalHostname(hostname) {
  const host = String(hostname || '').trim().toLowerCase();
  const localHosts = ['localhost', '127.0.0.1', '0.0.0.0', '[::1]'];
  if (localHosts.includes(host)) return true;

  // 检查私有IP地址（RFC 1918）
  const ipPattern = /^(10\.|172\.(1[6-9]|2[0-9]|3[0-1])\.|192\.168\.)/;
  if (ipPattern.test(host)) return true;

  return host.endsWith('.local') || host.endsWith('.test');
}

function resolveApiBase() {
  const configuredBase = normalizeBase(import.meta.env.VITE_API_BASE || '/api');
  if (typeof window === 'undefined' || !window.location) {
    return configuredBase || '/api';
  }

  const currentOrigin = normalizeBase(window.location.origin);
  const currentHostname = window.location.hostname;

  // 相对路径直接返回
  if (!configuredBase || configuredBase.startsWith('/')) {
    return configuredBase || '/api';
  }

  try {
    const configuredUrl = new URL(configuredBase);
    const configuredOrigin = normalizeBase(configuredUrl.origin);

    // 仅对完整URL进行同源检查
    if (isLocalHostname(currentHostname) && configuredOrigin !== currentOrigin) {
      console.warn('Local development detected, overriding external API base to /api');
      return '/api';
    }

    if (configuredOrigin === currentOrigin) {
      return `${configuredUrl.pathname}`.replace(/\/$/, '') || '/api';
    }
  } catch (error) {
    console.warn(`Invalid API base URL: ${configuredBase}, falling back to /api`, error);
    return '/api';
  }

  return configuredBase;
}
