            return this.buffer.slice(offset, offset + length);
        } else {
            throw new Error('Invalid offset or length');
        }
    }

    writeData(offset, data) {
        if (this.buffer && offset >= 0 && offset + data.length <= this.buffer.length) {
            data.copy(this.buffer, offset);
            fs.writeSync(this.fd, this.buffer, 0, this.buffer.length, 0);
        } else {
            throw new Error('Invalid offset or data length');
        }
    }

    close() {
        if (this.fd) {
            fs.closeSync(this.fd);
            this.fd = null;
            this.buffer = null;
            console.log('File closed.');
        }
    }
}

