```javascript
const fs = require('fs').promises;
const path = require('path');

class MemoryMappedFileHandler {
    constructor(filePath) {
        this.filePath = filePath;
        this.fd = null;
        this.buffer = null;
        this.isOpen = false;
    }

    async open() {
        try {
            this.fd = await fs.open(this.filePath, 'r+');
            const stats = await this.fd.stat();
            this.buffer = Buffer.alloc(stats.size);
            await this.fd.read(this.buffer, 0, stats.size, 0);
            this.isOpen = true;
            console.log('File opened and mapped to memory.');
        } catch (error) {
            console.error('Error opening file:', error);
            await this.close(); // 确保清理
            throw error;
        }
    }

    readData(offset, length) {
        if (!this.isOpen || !this.buffer) {
            throw new Error('File not open');
        }
        if (offset >= 0 && offset + length <= this.buffer.length) {
            return this.buffer.slice(offset, offset + length);
        } else {
            throw new Error('Invalid offset or length');
        }
    }

    async writeData(offset, data) {
        if (!this.isOpen || !this.buffer) {
            throw new Error('File not open');
        }
        if (offset >= 0 && offset + data.length <= this.buffer.length) {
            data.copy(this.buffer, offset);
            await this.fd.write(this.buffer, 0, this.buffer.length, 0);
        } else {
            throw new Error('Invalid offset or data length');
        }
    }

    async close() {
        if (this.fd) {
            await this.fd.close();
            this.fd = null;
        }
        this.buffer = null;
        this.isOpen = false;
        console.log('File closed and memory released.');
    }
}

// 使用示例
async function example() {
    const handler = new MemoryMappedFileHandler('data.bin');
    try {
        await handler.open();
        const data = handler.readData(0, 10);
        console.log('Read data:', data);
        await handler.writeData(10, Buffer.from('new data'));
    } catch (error) {
        console.error('Operation failed:', error);
    } finally {
        await handler.close();
    }
}

example();
```

