use std::sync::{Arc, Mutex};

struct Counter {
    value: Arc<Mutex<i32>>,
}

impl Counter {
    fn new() -> Self {
        Counter {
            value: Arc::new(Mutex::new(0)),
        }
    }

    fn increment(&self) {
        let mut val = self.value.lock().unwrap();
        *val += 1;
    }

    fn decrement(&self) {
        let mut val = self.value.lock().unwrap();
        *val -= 1;
    }

    fn get(&self) -> i32 {
        let val = self.value.lock().unwrap();
        *val
    }
}

fn main() {
    let counter = Counter::new();
    let counter_clone = Arc::clone(&counter.value);
    std::thread::spawn(move || {
        for _ in 0..10 {
            let mut val = counter_clone.lock().unwrap();
            *val += 1;
        }
    });
    for _ in 0..5 {
        counter.increment();
    }
    println!("Counter value: {}", counter.get());
}

