import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.TimeUnit;

public class DistributedLockService {
    private static ConcurrentHashMap<String, Boolean> lockMap = new ConcurrentHashMap<>();

    public boolean acquireLock(String lockKey, long timeoutMs) {
        long startTime = System.currentTimeMillis();
        while (System.currentTimeMillis() - startTime < timeoutMs) {
            if (lockMap.putIfAbsent(lockKey, true) == null) {
                return true;
            }
            try {
                Thread.sleep(100);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                return false;
            }
        }
        return false;
    }

    public void releaseLock(String lockKey) {
        lockMap.remove(lockKey);
    }

    public void processOrder(String orderId) {
        if (acquireLock(orderId, 5000)) {
            try {
                System.out.println("Processing order: " + orderId);
                // Simulate order processing
                Thread.sleep(2000);
            } catch (InterruptedException e) {
                e.printStackTrace();
            } finally {
                releaseLock(orderId);
            }
        } else {
            System.out.println("Failed to acquire lock for order: " + orderId);
        }
    }
}

