)

type SMSService struct {
    mu          sync.Mutex
    codeStore   map[string]string
    lastSent    map[string]time.Time
    rateLimit   int
}

func NewSMSService() *SMSService {
    return &SMSService{
        codeStore: make(map[string]string),
        lastSent:  make(map[string]time.Time),
        rateLimit: 5,
    }
}

func (s *SMSService) SendVerificationCode(phone string) error {
    s.mu.Lock()
    defer s.mu.Unlock()

    if last, ok := s.lastSent[phone]; ok {
        if time.Since(last) < time.Minute {
            return fmt.Errorf("rate limit exceeded")
        }
    }

    code := generateCode()
    s.codeStore[phone] = code
    s.lastSent[phone] = time.Now()

    // 模拟发送短信
    fmt.Printf("Sending SMS to %s: Your verification code is %s\n", phone, code)
    return nil
}

func (s *SMSService) VerifyCode(phone, code string) bool {
    s.mu.Lock()
    defer s.mu.Unlock()

    stored, ok := s.codeStore[phone]
    if !ok {
        return false
    }

    delete(s.codeStore, phone)
    delete(s.lastSent, phone)
    return stored == code
}

func generateCode() string {
    rand.Seed(time.Now().UnixNano())
    return fmt.Sprintf("%06d", rand.Intn(1000000))
}

