    err = json.Unmarshal(body, &tokenResp)
    if err != nil {
        http.Error(w, "Failed to parse token response", http.StatusInternalServerError)
        return
    }

    accessToken := tokenResp["access_token"].(string)
    fmt.Fprintf(w, "Access token: %s", accessToken)
}

