```typescript
import { Connection, Channel } from 'amqplib';

class MessageQueueProducer {
  private connection: Connection | null = null;
  private channel: Channel | null = null;
  private queueName: string;
  private isConnected: boolean = false;

  constructor(queueName: string) {
    this.queueName = queueName;
  }

  async connect(): Promise<void> {
    try {
      this.connection = await require('amqplib').connect('amqp://localhost');
      this.channel = await this.connection.createChannel();
      await this.channel.assertQueue(this.queueName, { durable: true });
      this.isConnected = true;
      console.log('Connected to message queue');
    } catch (error) {
      console.error('Failed to connect:', error);
      this.cleanup();
      throw error;
    }
  }

  async sendMessage(message: string): Promise<boolean> {
    if (!this.channel || !this.isConnected) {
      console.warn('Channel not initialized or disconnected');
      return false;
    }
    try {
      this.channel.sendToQueue(this.queueName, Buffer.from(message), { persistent: true });
      console.log(`Message sent: ${message}`);
      return true;
    } catch (error) {
      console.error('Failed to send message:', error);
      this.isConnected = false;
      this.cleanup();
      return false;
    }
  }

  private cleanup(): void {
    if (this.channel) {
      this.channel.close().catch(err => console.error('Error closing channel:', err));
      this.channel = null;
    }
    if (this.connection) {
      this.connection.close().catch(err => console.error('Error closing connection:', err));
      this.connection = null;
    }
    this.isConnected = false;
  }

  async close(): Promise<void> {
    this.cleanup();
    console.log('Connection closed');
  }

  async produceMessages(messages: string[]): Promise<number> {
    const sendPromises = messages.map(msg => this.sendMessage(msg));
    const results = await Promise.all(sendPromises);
    return results.filter(success => success).length;
  }
}

// 使用示例
async function main() {
  const producer = new MessageQueueProducer('task_queue');
  try {
    await producer.connect();
    const sentCount = await producer.produceMessages(['task1', 'task2', 'task3']);
    console.log(`Sent ${sentCount} messages successfully`);
  } catch (error) {
    console.error('Production failed:', error);
  } finally {
    await producer.close();
  }
}

main().catch(console.error);
```

