use reqwest::blocking::Client;
use std::time::Duration;
use std::sync::Arc;
use std::sync::atomic::{AtomicUsize, Ordering};
use std::thread;
use std::error::Error;

pub struct HttpClient {
    client: Client,
    timeout: Duration,
    retry_count: u32,
    request_counter: Arc<AtomicUsize>,
}

impl HttpClient {
    pub fn new(timeout_secs: u64, retry_count: u32) -> Self {
        let client = Client::builder()
            .timeout(Duration::from_secs(timeout_secs))
            .build()
            .expect("Failed to build HTTP client");
        HttpClient {
            client,
            timeout: Duration::from_secs(timeout_secs),
            retry_count,
            request_counter: Arc::new(AtomicUsize::new(0)),
        }
    }

    pub fn get(&self, url: &str) -> Result<String, Box<dyn Error>> {
        self.request_counter.fetch_add(1, Ordering::Relaxed);
        for attempt in 0..=self.retry_count {
            match self.client.get(url).timeout(self.timeout).send() {
                Ok(response) => {
                    if response.status().is_success() {
                        return Ok(response.text()?);
                    } else {
                        eprintln!("Request failed with status: {}", response.status());
                        if attempt == self.retry_count {
                            return Err(Box::new(std::io::Error::new(
                                std::io::ErrorKind::Other,
                                "Max retries exceeded",
                            )));
                        }
                        thread::sleep(Duration::from_millis(100 * (attempt + 1)));
                    }
                }
                Err(e) => {
                    eprintln!("Request error: {}", e);
                    if attempt == self.retry_count {
                        return Err(Box::new(e));
                    }
                    thread::sleep(Duration::from_millis(100 * (attempt + 1)));
                }
            }
        }
        unreachable!();
    }

    pub fn get_request_count(&self) -> usize {
        self.request_counter.load(Ordering::Relaxed)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_http_client() {
        let client = HttpClient::new(5, 3);
        let result = client.get("https://httpbin.org/get");
        assert!(result.is_ok());
        assert!(client.get_request_count() > 0);
    }
}

import java.util.LinkedList;
import java.util.Queue;

public class ConnectionPool {
    private Queue<Connection> pool;
    private int maxSize;

    public ConnectionPool(int maxSize) {
        this.maxSize = maxSize;
        this.pool = new LinkedList<>();
        for (int i = 0; i < maxSize; i++) {
            pool.add(new Connection());
        }
    }

    public Connection getConnection() {
        if (pool.isEmpty()) {
            throw new RuntimeException("No connections available");
        }
        return pool.poll();
    }

    public void releaseConnection(Connection conn) {
        if (pool.size() < maxSize) {
            pool.add(conn);
        }
    }
