const fs = require('fs');
const zlib = require('zlib');

function compressFile(inputPath, outputPath) {
    const readStream = fs.createReadStream(inputPath);
    const writeStream = fs.createWriteStream(outputPath);
    const gzip = zlib.createGzip();

    readStream.pipe(gzip).pipe(writeStream);

    writeStream.on('finish', () => {
        console.log(`File compressed to ${outputPath}`);
    });
}

function decompressFile(inputPath, outputPath) {
    const readStream = fs.createReadStream(inputPath);
    const writeStream = fs.createWriteStream(outputPath);
    const gunzip = zlib.createGunzip();

    readStream.pipe(gunzip).pipe(writeStream);

    writeStream.on('finish', () => {
        console.log(`File decompressed to ${outputPath}`);
    });
}

function processZipFile(zipFilePath, extractDir) {
    if (!fs.existsSync(zipFilePath)) {
        console.error('Zip file not found');
        return;
    }

    const readStream = fs.createReadStream(zipFilePath);
    const gunzip = zlib.createGunzip();
    let extractedData = '';

    gunzip.on('data', (chunk) => {
        extractedData += chunk.toString();
    });

    gunzip.on('end', () => {
        fs.writeFileSync(`${extractDir}/extracted.txt`, extractedData);
        console.log('Extraction complete');
    });

    readStream.pipe(gunzip);
}

module.exports = { compressFile, decompressFile, processZipFile };

