import threading
import time

class Logger:
    def __init__(self, filename):
        self.filename = filename
        self.file = open(filename, 'a')

    def log(self, message):
        timestamp = time.strftime('%Y-%m-%d %H:%M:%S')
        log_entry = f'{timestamp}: {message}\n'
        self.file.write(log_entry)
        self.file.flush()

    def close(self):
        self.file.close()

def worker(logger, thread_id):
    for i in range(5):
        logger.log(f'Thread {thread_id}: Log entry {i}')
        time.sleep(0.1)

if __name__ == '__main__':
    logger = Logger('app.log')
    threads = []
    for i in range(3):
        t = threading.Thread(target=worker, args=(logger, i))
        threads.append(t)
        t.start()
    for t in threads:
        t.join()
    logger.close()

import pika
import json
import time
from typing import Optional

class MessageQueueConsumer:
    def __init__(self, queue_name: str, host: str = 'localhost'):
        self.queue_name = queue_name
        self.host = host
        self.connection: Optional[pika.BlockingConnection] = None
        self.channel: Optional[pika.adapters.blocking_connection.BlockingChannel] = None

    def connect(self) -> None:
        try:
            self.connection = pika.BlockingConnection(pika.ConnectionParameters(host=self.host))
            self.channel = self.connection.channel()
            self.channel.queue_declare(queue=self.queue_name, durable=True)
            print(f"Connected to queue: {self.queue_name}")
        except Exception as e:
            print(f"Connection failed: {e}")

    def process_message(self, body: bytes) -> None:
        try:
            data = json.loads(body.decode('utf-8'))
            print(f"Processing message: {data}")
            # Simulate message processing
            time.sleep(0.1)
            if 'error' in data:
                raise ValueError("Simulated processing error")
            print("Message processed successfully")
        except json.JSONDecodeError as e:
            print(f"JSON decode error: {e}")
        except Exception as e:
            print(f"Processing error: {e}")

    def consume(self) -> None:
        if not self.channel:
            self.connect()
        try:
            self.channel.basic_consume(queue=self.queue_name, on_message_callback=self.callback, auto_ack=True)
            print("Starting consumer...")
            self.channel.start_consuming()
        except Exception as e:
            print(f"Consume error: {e}")
            if self.connection:
                self.connection.close()

    def callback(self, ch, method, properties, body: bytes) -> None:
        self.process_message(body)

if __name__ == "__main__":
    consumer = MessageQueueConsumer(queue_name="task_queue")
    consumer.consume()

