CREATE OR REPLACE FUNCTION match_tags(user_id INT, tag_list TEXT[]) RETURNS TABLE(post_id INT, relevance_score FLOAT) AS $$
DECLARE
    tag_array TEXT[];
    post_record RECORD;
    score FLOAT;
    tag_count INT;
BEGIN
    tag_array := tag_list;
    FOR post_record IN SELECT p.id, p.tags FROM posts p WHERE p.user_id = user_id LOOP
        score := 0.0;
        tag_count := 0;
        FOR i IN 1..array_length(tag_array, 1) LOOP
            IF post_record.tags @> ARRAY[tag_array[i]] THEN
                score := score + 1.0;
                tag_count := tag_count + 1;
            END IF;
        END LOOP;
        IF tag_count > 0 THEN
            score := score / tag_count;
        END IF;
        IF score > 0.0 THEN
            post_id := post_record.id;
            relevance_score := score;
            RETURN NEXT;
        END IF;
    END LOOP;
    RETURN;
END;
$$ LANGUAGE plpgsql;

