DECLARE
    result TEXT := '';
    middleware_name VARCHAR(50);
    middleware_cursor CURSOR FOR SELECT name FROM middleware_table ORDER BY priority;
BEGIN
    OPEN middleware_cursor;
    LOOP
        FETCH middleware_cursor INTO middleware_name;
        EXIT WHEN NOT FOUND;
        IF middleware_name = 'auth_middleware' THEN
            result := result || 'Authenticated user ' || user_id || '; ';
