CREATE PROCEDURE AcquireLock(IN lock_key VARCHAR(255), IN timeout_seconds INT)
BEGIN
    DECLARE lock_id INT;
    DECLARE current_time TIMESTAMP DEFAULT CURRENT_TIMESTAMP;
    DECLARE expiry_time TIMESTAMP;
    SET expiry_time = DATE_ADD(current_time, INTERVAL timeout_seconds SECOND);
    INSERT INTO distributed_locks (lock_key, acquired_at, expires_at) 
    VALUES (lock_key, current_time, expiry_time)
    ON DUPLICATE KEY UPDATE 
        acquired_at = IF(expires_at < CURRENT_TIMESTAMP, current_time, acquired_at),
        expires_at = IF(expires_at < CURRENT_TIMESTAMP, expiry_time, expires_at);
    SELECT LAST_INSERT_ID() INTO lock_id;
    IF lock_id > 0 THEN
        SELECT 'Lock acquired' AS result;
    ELSE
        SELECT 'Lock not acquired' AS result;
    END IF;
END;

