    @Username NVARCHAR(50),
    @Password NVARCHAR(50)
AS
BEGIN
    DECLARE @StoredPassword NVARCHAR(50);
    DECLARE @UserId INT;

    -- 查询用户信息
    SET @StoredPassword = (SELECT Password FROM Users WHERE Username = @Username);

    IF @StoredPassword IS NOT NULL
