                if os.path.isfile(filepath) and filename.endswith('.txt'):
                    with open(filepath, 'r') as in_f:
                        lines = in_f.readlines()
                        out_f.write(f"{filename}: {len(lines)} 行\n")
    except Exception as e:
        print(f"处理文件时出错: {e}")
