    p_order_id INT,
    p_new_status VARCHAR(50),
    p_user_id INT
)
AS $$
DECLARE
    v_current_status VARCHAR(50);
    v_order_count INT;
BEGIN
    -- 检查订单是否存在
    SELECT status INTO v_current_status
    FROM orders
    WHERE order_id = p_order_id;

    IF v_current_status IS NULL THEN
        RAISE EXCEPTION 'Order not found';
    END IF;

    -- 验证状态转换是否允许
    IF v_current_status = 'CANCELLED' AND p_new_status != 'CANCELLED' THEN
        RAISE EXCEPTION 'Cannot update status from CANCELLED';
    END IF;

    -- 更新订单状态
    UPDATE orders
    SET status = p_new_status,
        updated_at = NOW(),
        updated_by = p_user_id
    WHERE order_id = p_order_id;

    -- 记录状态变更历史
    INSERT INTO order_status_history (order_id, old_status, new_status, changed_at, changed_by)
    VALUES (p_order_id, v_current_status, p_new_status, NOW(), p_user_id);

    -- 检查是否有重复订单（业务逻辑示例）
    SELECT COUNT(*) INTO v_order_count
    FROM orders
    WHERE customer_id = (SELECT customer_id FROM orders WHERE order_id = p_order_id)
      AND status = 'PENDING';

    IF v_order_count > 5 THEN
        RAISE EXCEPTION 'Too many pending orders for this customer';
    END IF;

    COMMIT;
EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RAISE;
END;
$$ LANGUAGE plpgsql;

