DECLARE
    retry_count INT := 0;
    max_retries INT := 3;
BEGIN
    WHILE retry_count < max_retries LOOP
        BEGIN
            INSERT INTO orders (id, customer, total) VALUES (order_id, customer_name, amount);
            EXIT;
        EXCEPTION WHEN OTHERS THEN
            retry_count := retry_count + 1;
