import redis
import time

class DistributedLock:
    def __init__(self, redis_client, lock_key, timeout=10):
        self.redis_client = redis_client
        self.lock_key = lock_key
        self.timeout = timeout
        self.lock_acquired = False

    def acquire(self):
        current_time = time.time()
        expire_time = current_time + self.timeout
        success = self.redis_client.setnx(self.lock_key, expire_time)
        if success:
            self.lock_acquired = True
            return True
        else:
            existing_expire = float(self.redis_client.get(self.lock_key))
            if existing_expire < current_time:
                new_expire = current_time + self.timeout
                old_expire = self.redis_client.getset(self.lock_key, new_expire)
                if float(old_expire) == existing_expire:
                    self.lock_acquired = True
                    return True
        return False

    def release(self):
        if self.lock_acquired:
            self.redis_client.delete(self.lock_key)
            self.lock_acquired = False
        else:
            print("Lock not acquired, cannot release.")

# 示例使用
redis_client = redis.Redis(host='localhost', port=6379, db=0)
lock = DistributedLock(redis_client, "resource_lock")
if lock.acquire():
    try:
        # 模拟业务操作
        print("Lock acquired, performing task...")
        time.sleep(5)
    finally:
        lock.release()
else:
    print("Failed to acquire lock.")

