package main

import (
    "fmt"
    "math/big"
)

func calculatePayment(amountStr string, discount float64) (*big.Float, error) {
    // 使用 big.Float 处理高精度金额
    amount := new(big.Float)
    amount.SetPrec(128) // 设置足够精度
    _, ok := amount.SetString(amountStr)
    if !ok {
        return nil, fmt.Errorf("无效金额格式: %s", amountStr)
    }

    // 验证折扣范围
    if discount < 0 || discount > 1 {
        return nil, fmt.Errorf("折扣必须在 0 到 1 之间")
    }

    // 应用折扣
    discountMultiplier := new(big.Float).SetFloat64(1 - discount)
    discountedAmount := new(big.Float).Mul(amount, discountMultiplier)

    // 检查金额是否非负
    if discountedAmount.Sign() < 0 {
        return nil, fmt.Errorf("金额不能为负数")
    }

    return discountedAmount, nil
}

func main() {
    // 示例调用
    result, err := calculatePayment("100.50", 0.1)
    if err != nil {
