    def add_task(self, task_func, interval):
        self.tasks.append({'func': task_func, 'interval': interval})

    def start(self):
        self.running = True
        for task in self.tasks:
            thread = threading.Thread(target=self._run_task, args=(task,))
            thread.start()

    def _run_task(self, task):
        while self.running:
            try:
                task['func']()
            except Exception as e:
                print(f"Error in task: {e}")
            time.sleep(task['interval'])

    def stop(self):
        self.running = False

