const mysql = require('mysql');

class Database {
  constructor(config) {
    this.pool = mysql.createPool({
      host: config.host,
      user: config.user,
      password: config.password,
      database: config.database,
      connectionLimit: config.connectionLimit || 10,
      waitForConnections: true,
      queueLimit: config.queueLimit || 100
    });
  }

  async query(sql, params = []) {
    return new Promise((resolve, reject) => {
      this.pool.getConnection((err, connection) => {
        if (err) {
          reject(err);
          return;
        }
        connection.query(sql, params, (error, results) => {
          connection.release();
          if (error) {
            reject(error);
          } else {
            resolve(results);
          }
        });
      });
    });
  }

  async getUserById(id) {
    if (typeof id !== 'number' || id <= 0) {
      throw new Error('Invalid id: must be a positive number');
    }
    const sql = 'SELECT * FROM users WHERE id = ?';
    return this.query(sql, [id]);
  }

  async searchUsers(name, limit = 10) {
    if (typeof name !== 'string') {
      throw new Error('Invalid name: must be a string');
    }
    if (typeof limit !== 'number' || limit <= 0) {
      throw new Error('Invalid limit: must be a positive number');
    }
    const sql = 'SELECT * FROM users WHERE name LIKE ? LIMIT ?';
    return this.query(sql, [`%${name}%`, limit]);
  }

  async updateUserStatus(id, status) {
    if (typeof id !== 'number' || id <= 0) {
      throw new Error('Invalid id: must be a positive number');
    }
    if (typeof status !== 'string' || !['active', 'inactive', 'pending'].includes(status)) {
      throw new Error('Invalid status: must be a valid string');
    }
    const sql = 'UPDATE users SET status = ? WHERE id = ?';
    return this.query(sql, [status, id]);
  }

  async close() {
    return new Promise((resolve, reject) => {
      this.pool.end((err) => {
        if (err) {
          reject(err);
        } else {
          resolve();
        }
      });
    });
  }
