import (
    "context"
    "database/sql"
    "fmt"
    "log"
    "time"
    _ "github.com/go-sql-driver/mysql"
)

type User struct {
    ID   int
    Name string
}

func fetchUsersWithCursor(ctx context.Context, db *sql.DB, batchSize int) ([]User, error) {
    rows, err := db.QueryContext(ctx, "SELECT id, name FROM users ORDER BY id")
    if err != nil {
        return nil, fmt.Errorf("query failed: %w", err)
    }
    defer rows.Close()

    var users []User
    for rows.Next() {
        var user User
        if err := rows.Scan(&user.ID, &user.Name); err != nil {
            log.Printf("scan error: %v", err)
            continue
        }
        users = append(users, user)
        if len(users) >= batchSize {
            break
        }
    }
    if err := rows.Err(); err != nil {
        return nil, fmt.Errorf("rows error: %w", err)
    }
    return users, nil
}

func processUsers(ctx context.Context, db *sql.DB) error {
    batchSize := 100
    for {
        users, err := fetchUsersWithCursor(ctx, db, batchSize)
        if err != nil {
            return fmt.Errorf("fetch users failed: %w", err)
        }
        if len(users) == 0 {
            break
        }
        for _, user := range users {
            fmt.Printf("Processing user: %d, %s\n", user.ID, user.Name)
        }
        time.Sleep(100 * time.Millisecond)
    }
    return nil
}

