```go
package main

import (
    "context"
    "fmt"
    "io"
    "os"
    "os/exec"
    "path/filepath"
    "sync"
    "time"
)

type TranscodeTask struct {
    InputPath  string
    OutputPath string
    Format     string
    Bitrate    string
}

func transcodeVideo(ctx context.Context, task TranscodeTask, wg *sync.WaitGroup, errCh chan<- error) {
    defer wg.Done()

    // 验证输入文件
    if _, err := os.Stat(task.InputPath); err != nil {
        errCh <- fmt.Errorf("输入文件无效: %s, 错误: %v", task.InputPath, err)
        return
    }

    // 使用 context 控制超时
    cmdCtx, cancel := context.WithTimeout(ctx, 5*time.Minute)
    defer cancel()

    cmd := exec.CommandContext(cmdCtx, "ffmpeg", "-i", task.InputPath, "-c:v", "libx264", "-b:v", task.Bitrate, "-f", task.Format, task.OutputPath)

    output, err := cmd.CombinedOutput()
    if err != nil {
        // 清理可能的部分输出文件
        os.Remove(task.OutputPath)
        errCh <- fmt.Errorf("转码失败: %s, 错误: %v, 输出: %s", task.InputPath, err, output)
        return
    }

    if len(output) > 0 {
        fmt.Printf("转码输出: %s\n", output)
    }

    // 检查输出文件
    if _, err := os.Stat(task.OutputPath); err != nil {
        errCh <- fmt.Errorf("输出文件未生成: %s", task.OutputPath)
    }
}

func processTranscodeTasks(tasks []TranscodeTask) error {
    var wg sync.WaitGroup
    errCh := make(chan error, len(tasks))
    ctx := context.Background()

    for _, task := range tasks {
        // 标准化路径
        task.InputPath = filepath.Clean(task.InputPath)
        task.OutputPath = filepath.Clean(task.OutputPath)

        wg.Add(1)
        go transcodeVideo(ctx, task, &wg, errCh)
    }

    wg.Wait()
    close(errCh)

    // 收集错误
    var errors []string
    for err := range errCh {
        errors = append(errors, err.Error())
    }

    if len(errors) > 0 {
        return fmt.Errorf("转码任务完成，但有错误: %v", errors)
    }

    fmt.Println("所有转码任务成功完成")
    return nil
}

func main() {
    tasks := []TranscodeTask{
        {"input/video1.mp4", "output/video1_h264.mp4", "mp4", "1M"},
        {"input/video2.mov", "output/video2_h264.mp4", "mp4", "2M"},
        {"input/video3.avi", "output/video3_h264.mp4", "mp4", "500k"},
    }

    if err := processTranscodeTasks(tasks); err != nil {
        fmt.Printf("处理失败: %v\n", err)
        os.Exit(1)
    }
}
```

