import java.util.Set;

public class DataSyncService {
    public void syncAllData(List<String> sourceData, List<String> targetData) {
        Set<String> targetSet = new HashSet<>(targetData); // 将目标列表转换为 HashSet 以提高查找效率
        for (String data : sourceData) {
            if (!targetSet.contains(data)) {
                targetData.add(data);
                targetSet.add(data); // 保持 HashSet 与目标列表同步
            }
        }
        System.out.println("全量数据同步完成，目标数据大小：" + targetData.size());
    }

    public static void main(String[] args) {
        DataSyncService service = new DataSyncService();
        List<String> source = new ArrayList<>();
        source.add("item1");
        source.add("item2");
        source.add("item3");
        List<String> target = new ArrayList<>();
        service.syncAllData(source, target);
    }
}
