                if (item && typeof item === 'object') {
                    doc.text(`Item: ${item.name || 'N/A'}, Price: $${item.price || 0}`);
                }
            });
        }

        doc.end();
        writeStream.on('finish', () => {
            console.log('PDF generated successfully at ' + outputPath);
