CREATE OR REPLACE PROCEDURE process_orders()
LANGUAGE plpgsql
AS $$
DECLARE
    conn_pool_size INTEGER := 10;
    conn_pool_used INTEGER := 0;
    conn_handle RECORD;
    order_id INTEGER;
    order_amount DECIMAL(10,2);
    sql_query TEXT;
BEGIN
    -- 初始化连接池
    FOR i IN 1..conn_pool_size LOOP
        PERFORM dblink_connect('conn_' || i, 'host=localhost dbname=orders user=admin password=secret');
    END LOOP;

    -- 处理订单
    FOR order_id IN SELECT id FROM orders WHERE status = 'pending' LOOP
        -- 获取连接
        conn_pool_used := conn_pool_used + 1;
        IF conn_pool_used > conn_pool_size THEN
            conn_pool_used := 1;
        END IF;
        conn_handle := dblink_get_connection('conn_' || conn_pool_used);

        -- 执行查询
        sql_query := 'SELECT amount FROM orders WHERE id = ' || order_id;
        EXECUTE sql_query INTO order_amount;

        -- 更新订单状态
        sql_query := 'UPDATE orders SET status = ''processed'', processed_at = NOW() WHERE id = ' || order_id;
        PERFORM dblink_exec(conn_handle, sql_query);

        -- 记录日志
        INSERT INTO order_logs (order_id, amount, processed_at) VALUES (order_id, order_amount, NOW());
    END LOOP;

    -- 关闭连接池
    FOR i IN 1..conn_pool_size LOOP
        PERFORM dblink_disconnect('conn_' || i);
    END LOOP;
END;
$$;

