use std::fs::File;
use std::io::{self, Read};
use std::path::Path;

struct AudioStreamReader {
    file: File,
    buffer: Vec<u8>,
}

impl AudioStreamReader {
    fn new(path: &str) -> io::Result<Self> {
        let file = File::open(path)?;
        Ok(AudioStreamReader {
            file,
            buffer: Vec::new(),
        })
    }

    fn read_chunk(&mut self, size: usize) -> io::Result<usize> {
        self.buffer.resize(size, 0);
        let bytes_read = self.file.read(&mut self.buffer)?;
        self.buffer.truncate(bytes_read);
        Ok(bytes_read)
    }

    fn process_audio(&mut self) -> io::Result<()> {
        let bytes_read = self.read_chunk(1024)?;
        if bytes_read == 0 {
            return Ok(()); // End of stream
        }
        println!("Processing audio chunk of {} bytes", bytes_read);
        // Simulate audio processing
        Ok(())
    }
}

impl Drop for AudioStreamReader {
    fn drop(&mut self) {
        if let Err(e) = self.file.sync_all() {
            eprintln!("Failed to sync file on drop: {}", e);
        }
    }
}

fn main() -> io::Result<()> {
    let mut reader = AudioStreamReader::new("audio.wav")?;
    loop {
        match reader.process_audio() {
            Ok(_) => {},
            Err(e) if e.kind() == io::ErrorKind::UnexpectedEof => break,
            Err(e) => return Err(e),
        }
    }
    Ok(())
}
```

