CREATE OR REPLACE PROCEDURE call_api_with_retry(
    p_url VARCHAR2,
    p_payload CLOB,
    p_max_retries NUMBER DEFAULT 3,
    p_retry_delay NUMBER DEFAULT 1
) AS
    l_response CLOB;
    l_http_request UTL_HTTP.REQ;
    l_http_response UTL_HTTP.RESP;
    l_retry_count NUMBER := 0;
    l_success BOOLEAN := FALSE;
BEGIN
    WHILE l_retry_count < p_max_retries AND NOT l_success LOOP
        BEGIN
            l_http_request := UTL_HTTP.BEGIN_REQUEST(p_url, 'POST', 'HTTP/1.1');
            UTL_HTTP.SET_HEADER(l_http_request, 'Content-Type', 'application/json');
            UTL_HTTP.SET_HEADER(l_http_request, 'Content-Length', LENGTH(p_payload));
            UTL_HTTP.WRITE_TEXT(l_http_request, p_payload);
            l_http_response := UTL_HTTP.GET_RESPONSE(l_http_request);
            UTL_HTTP.READ_TEXT(l_http_response, l_response);
            UTL_HTTP.END_RESPONSE(l_http_response);
            l_success := TRUE;
            DBMS_OUTPUT.PUT_LINE('API call successful: ' || l_response);
        EXCEPTION
            WHEN OTHERS THEN
                l_retry_count := l_retry_count + 1;
                IF l_retry_count < p_max_retries THEN
                    DBMS_OUTPUT.PUT_LINE('Retry ' || l_retry_count || ' after error: ' || SQLERRM);
                    DBMS_LOCK.SLEEP(p_retry_delay);
                ELSE
                    DBMS_OUTPUT.PUT_LINE('Max retries reached: ' || SQLERRM);
                    RAISE;
                END IF;
        END;
    END LOOP;
END call_api_with_retry;

