CREATE OR REPLACE FUNCTION check_admin_permission(user_id INT, resource_id INT) RETURNS BOOLEAN AS $$
DECLARE
    is_admin BOOLEAN;
    resource_owner_id INT;
    current_time TIMESTAMP := NOW();
    session_timeout INTERVAL := '30 minutes';
    session_valid BOOLEAN;
BEGIN
    -- Check if user is an admin
    SELECT admin INTO is_admin FROM users WHERE id = user_id;
    IF NOT FOUND THEN
        RETURN FALSE;
    END IF;
    IF NOT is_admin THEN
        RETURN FALSE;
    END IF;

    -- Check if the resource exists and get its owner
    SELECT owner_id INTO resource_owner_id FROM resources WHERE id = resource_id;
    IF NOT FOUND THEN
        RETURN FALSE;
    END IF;

    -- Verify session is still valid for the admin
    SELECT (last_activity + session_timeout > current_time) INTO session_valid FROM admin_sessions WHERE user_id = user_id;
    IF NOT FOUND THEN
        RETURN FALSE;
    END IF;
    IF NOT session_valid THEN
        RETURN FALSE;
    END IF;

    -- Additional check: admin can only access resources owned by themselves or by subordinates
    IF resource_owner_id != user_id THEN
        DECLARE
            is_subordinate BOOLEAN;
        BEGIN
            SELECT EXISTS(SELECT 1 FROM subordinates WHERE admin_id = user_id AND user_id = resource_owner_id) INTO is_subordinate;
            IF NOT is_subordinate THEN
                RETURN FALSE;
            END IF;
        END;
    END IF;

    -- Log the access attempt
    INSERT INTO access_logs (user_id, resource_id, accessed_at, status) VALUES (user_id, resource_id, current_time, 'GRANTED');

    RETURN TRUE;
EXCEPTION
    WHEN OTHERS THEN
        -- Log error and return false
        INSERT INTO error_logs (user_id, error_message, occurred_at) VALUES (user_id, SQLERRM, current_time);
        RETURN FALSE;
END;
$$ LANGUAGE plpgsql;

