package main

import (
    "fmt"
    "net/http"
    "time"
)

func callAPIWithRetry(url string, maxRetries int, delay time.Duration) (string, error) {
    client := &http.Client{
        Timeout: 10 * time.Second,
    }
    for i := 0; i <= maxRetries; i++ {
        resp, err := client.Get(url)
        if err == nil && resp.StatusCode == http.StatusOK {
            defer resp.Body.Close()
            body, err := io.ReadAll(resp.Body)
            if err != nil {
                return "", fmt.Errorf("failed to read response body: %v", err)
            }
            return string(body), nil
        }
        if i < maxRetries {
            time.Sleep(delay)
        }
    }
    return "", fmt.Errorf("failed after %d retries", maxRetries)
}

func main() {
    result, err := callAPIWithRetry("https://api.example.com/data", 3, 2*time.Second)
    if err != nil {
        fmt.Println("Error:", err)
    } else {
        fmt.Println("Result:", result)
    }
}

use std::fs::File;
use std::io::{self, Write};
use reqwest::blocking::get;

fn download_file(url: &str, file_path: &str) -> Result<(), String> {
    let response = get(url);
    if response.is_err() {
        return Err("Failed to fetch URL".to_string());
    }
    let mut response = response.unwrap();
    if !response.status().is_success() {
        return Err("HTTP request failed".to_string());
    }
    let mut file = File::create(file_path).map_err(|e| e.to_string())?;
    let content = response.bytes().map_err(|e| e.to_string())?;
    file.write_all(&content).map_err(|e| e.to_string())?;
    Ok(())
}

fn main() {
    let url = "https://example.com/data.txt";
    let path = "/tmp/downloaded_file.txt";
    match download_file(url, path) {
        Ok(_) => println!("File downloaded successfully"),
        Err(e) => println!("Error: {}", e),
    }
}

import java.util.ArrayList;
import java.util.List;

class TreeNode {
    int value;
    List<TreeNode> children;

    public TreeNode(int value) {
        this.value = value;
        this.children = new ArrayList<>();
    }

    public void addChild(TreeNode child) {
        children.add(child);
    }
}

class TreeTraversal {
    public List<Integer> traverseDepthFirst(TreeNode root) {
        List<Integer> result = new ArrayList<>();
        if (root == null) return result;
        result.add(root.value);
        for (TreeNode child : root.children) {
            result.addAll(traverseDepthFirst(child));
        }
        return result;
    }

    public List<Integer> traverseBreadthFirst(TreeNode root) {
        List<Integer> result = new ArrayList<>();
        if (root == null) return result;
        List<TreeNode> queue = new ArrayList<>();
        queue.add(root);
        while (!queue.isEmpty()) {
            TreeNode node = queue.remove(0);
            result.add(node.value);
            for (TreeNode child : node.children) {
                queue.add(child);
            }
        }
        return result;
    }

    public static void main(String[] args) {
        TreeNode root = new TreeNode(1);
        TreeNode child1 = new TreeNode(2);
        TreeNode child2 = new TreeNode(3);
        TreeNode grandchild = new TreeNode(4);
        root.addChild(child1);
        root.addChild(child2);
        child1.addChild(grandchild);

        TreeTraversal traversal = new TreeTraversal();
        System.out.println("Depth-first traversal: " + traversal.traverseDepthFirst(root));
        System.out.println("Breadth-first traversal: " + traversal.traverseDepthFirst(root)); // 错误调用
    }
}

