use std::collections::HashMap;
use std::sync::{Arc, Mutex};
use std::thread;

struct UserInfo {
    id: u32,
    name: String,
    email: String,
    age: u8,
}

struct UserManager {
    users: Arc<Mutex<HashMap<u32, UserInfo>>>,
}

impl UserManager {
    fn new() -> Self {
        UserManager {
            users: Arc::new(Mutex::new(HashMap::new())),
        }
    }

    fn add_user(&self, user: UserInfo) -> Result<(), String> {
        let mut users = self.users.lock().unwrap();
        if users.contains_key(&user.id) {
            return Err("User ID already exists".to_string());
        }
        users.insert(user.id, user);
        Ok(())
    }

    fn get_user(&self, id: u32) -> Option<UserInfo> {
        let users = self.users.lock().unwrap();
        users.get(&id).cloned()
    }

    fn update_email(&self, id: u32, new_email: String) -> Result<(), String> {
        let mut users = self.users.lock().unwrap();
        if let Some(user) = users.get_mut(&id) {
            user.email = new_email;
            Ok(())
        } else {
            Err("User not found".to_string())
        }
    }

    fn process_users_concurrently(&self) {
        let handles: Vec<_> = (0..5)
            .map(|i| {
                let manager = Arc::clone(&self.users);
                thread::spawn(move || {
                    let mut users = manager.lock().unwrap();
                    for (id, user) in users.iter_mut() {
                        if user.age > 18 {
                            user.email = format!("updated_{}@example.com", i);
                        }
                    }
                })
            })
            .collect();
        for handle in handles {
            handle.join().unwrap();
        }
    }
}

fn main() {
    let manager = UserManager::new();
    manager.add_user(UserInfo {
        id: 1,
        name: "Alice".to_string(),
        email: "alice@example.com".to_string(),
        age: 25,
    }).unwrap();
    manager.process_users_concurrently();
    println!("User email: {:?}", manager.get_user(1).unwrap().email);
}

