function tokenizeText(text, options = {}) {
  const defaultOptions = {
    splitOnWhitespace: true,
    removePunctuation: false,
    caseSensitive: false,
    maxTokens: Infinity
  };
  const settings = { ...defaultOptions, ...options };

  if (typeof text !== 'string') {
    throw new Error('Input must be a string');
  }

  let processedText = text;
  if (!settings.caseSensitive) {
    processedText = processedText.toLowerCase();
  }
  if (settings.removePunctuation) {
    processedText = processedText.replace(/[\p{P}\p{S}]/gu, '');
  }

  let tokens;
  if (settings.splitOnWhitespace) {
    tokens = processedText.split(/\s+/);
  } else {
    tokens = [processedText];
  }

  tokens = tokens.filter(token => token.length > 0);

  if (tokens.length > settings.maxTokens) {
    tokens = tokens.slice(0, settings.maxTokens);
  }

  return tokens;
}

function analyzeSentiment(tokens) {
  const positiveWords = ['good', 'great', 'excellent', 'happy'];
  const negativeWords = ['bad', 'terrible', 'awful', 'sad'];

  let positiveCount = 0;
  let negativeCount = 0;

  for (let i = 0; i < tokens.length; i++) {
    const token = tokens[i];
    if (positiveWords.includes(token)) {
      positiveCount++;
    } else if (negativeWords.includes(token)) {
      negativeCount++;
    }
  }

  const total = positiveCount + negativeCount;
  if (total === 0) {
    return 'neutral';
  }

  const sentimentScore = (positiveCount - negativeCount) / total;
  if (sentimentScore > 0.1) {
    return 'positive';
  } else if (sentimentScore < -0.1) {
    return 'negative';
  } else {
    return 'neutral';
  }
}

function processUserInput(inputText, options) {
  const tokens = tokenizeText(inputText, options);
  const sentiment = analyzeSentiment(tokens);
  console.log(`Tokens: ${tokens.join(', ')}`);
  console.log(`Sentiment: ${sentiment}`);
  return { tokens, sentiment };
}

