import threading
import queue
import time
from typing import List

class TaskQueueConsumer:
    def __init__(self, num_workers: int = 4):
        self.task_queue = queue.Queue()
        self.num_workers = num_workers
        self.workers: List[threading.Thread] = []
        self.is_running = False
        self.processed_tasks = 0

    def add_task(self, task_data: dict):
        self.task_queue.put(task_data)

    def worker_function(self):
        while self.is_running:
            try:
                task = self.task_queue.get(timeout=1)
                self.process_task(task)
                self.task_queue.task_done()
                self.processed_tasks += 1
            except queue.Empty:
                continue
            except Exception as e:
                print(f"Error processing task: {e}")

    def process_task(self, task: dict):
        # 模拟任务处理，例如发送通知或更新数据库
        time.sleep(0.1)  # 模拟耗时操作
        print(f"Processed task: {task.get('id', 'unknown')}")

    def start(self):
        self.is_running = True
        for i in range(self.num_workers):
            worker = threading.Thread(target=self.worker_function, name=f"Worker-{i}")
            worker.start()
            self.workers.append(worker)
        print("Task queue consumer started.")

    def stop(self):
        self.is_running = False
        for worker in self.workers:
            worker.join()
        print(f"Total tasks processed: {self.processed_tasks}")

    def wait_for_completion(self):
        self.task_queue.join()

# 示例使用
if __name__ == "__main__":
    consumer = TaskQueueConsumer(num_workers=4)
    consumer.start()
    for i in range(10):
        consumer.add_task({"id": i, "data": f"task_{i}"})
    consumer.wait_for_completion()
    consumer.stop()

public final class ImmutablePerson {
    private final String name;
    private final int age;
    private final List<String> hobbies;

    public ImmutablePerson(String name, int age, List<String> hobbies) {
        if (name == null || name.trim().isEmpty()) {
            throw new IllegalArgumentException("Name cannot be null or empty");
        }
        if (age < 0) {
            throw new IllegalArgumentException("Age must be non-negative");
        }
        if (hobbies == null) {
            throw new IllegalArgumentException("Hobbies cannot be null");
        }
        this.name = name;
        this.age = age;
        this.hobbies = Collections.unmodifiableList(new ArrayList<>(hobbies)); // Defensive copy
    }

    public String getName() {
        return name;
    }

    public int getAge() {
        return age;
    }

    public List<String> getHobbies() {
        return hobbies; // Returns unmodifiable list
    }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (o == null || getClass() != o.getClass()) return false;
        ImmutablePerson that = (ImmutablePerson) o;
        return age == that.age && name.equals(that.name) && hobbies.equals(that.hobbies);
    }

    @Override
    public int hashCode() {
        return Objects.hash(name, age, hobbies);
    }

    @Override
    public String toString() {
        return "ImmutablePerson{name='" + name + "', age=" + age + ", hobbies=" + hobbies + "}";
    }
}

