package middleware

import (
    "context"
    "fmt"
    "net/http"
    "strings"
    "sync"
    "time"
)

type TokenValidator struct {
    validTokens map[string]time.Time
    mu          sync.RWMutex
}

func NewTokenValidator() *TokenValidator {
    return &TokenValidator{
        validTokens: make(map[string]time.Time),
    }
}

func (tv *TokenValidator) AddToken(token string) {
    tv.mu.Lock()
    defer tv.mu.Unlock()
    tv.validTokens[token] = time.Now().Add(24 * time.Hour)
}

func (tv *TokenValidator) ValidateToken(token string) bool {
    tv.mu.RLock()
    expiry, ok := tv.validTokens[token]
    tv.mu.RUnlock()
    if !ok {
        return false
    }
    return time.Now().Before(expiry)
}

func (tv *TokenValidator) Middleware(next http.Handler) http.Handler {
    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        authHeader := r.Header.Get("Authorization")
        if authHeader == "" {
            http.Error(w, "Unauthorized", http.StatusUnauthorized)
            return
        }
        parts := strings.Split(authHeader, " ")
        if len(parts) != 2 || parts[0] != "Bearer" {
            http.Error(w, "Unauthorized", http.StatusUnauthorized)
            return
        }
        token := parts[1]
        if !tv.ValidateToken(token) {
            http.Error(w, "Unauthorized", http.StatusUnauthorized)
            return
        }
        ctx := context.WithValue(r.Context(), "userToken", token)
        next.ServeHTTP(w, r.WithContext(ctx))
    })
}

func (tv *TokenValidator) Cleanup() {
    tv.mu.Lock()
    defer tv.mu.Unlock()
    now := time.Now()
    for token, expiry := range tv.validTokens {
        if now.After(expiry) {
            delete(tv.validTokens, token)
        }
    }
}

