import java.util.concurrent.atomic.AtomicInteger;

public class DatabaseConnectionManager {
    private static DatabaseConnectionManager instance;
    private AtomicInteger connectionCount;
    private boolean initialized;

    private DatabaseConnectionManager() {
        connectionCount = new AtomicInteger(0);
        initialized = false;
        // 模拟初始化数据库连接的耗时操作
        try {
            Thread.sleep(100);
        } catch (InterruptedException e) {
            e.printStackTrace();
        }
        initialized = true;
    }

    public static DatabaseConnectionManager getInstance() {
        if (instance == null) {
            synchronized (DatabaseConnectionManager.class) {
                if (instance == null) {
                    instance = new DatabaseConnectionManager();
                }
            }
        }
        return instance;
    }

    public void connect() {
        if (!initialized) {
            throw new IllegalStateException("Database connection manager not initialized");
        }
        int current = connectionCount.incrementAndGet();
        System.out.println("Connection established. Total connections: " + current);
    }

    public void disconnect() {
        if (connectionCount.get() > 0) {
            int current = connectionCount.decrementAndGet();
            System.out.println("Connection closed. Remaining connections: " + current);
        }
    }

    public int getConnectionCount() {
        return connectionCount.get();
    }
}

