import requests
import time
from typing import Optional, Dict, Any

class RetryHTTPClient:
    def __init__(self, max_retries: int = 3, timeout: float = 5.0):
        self.max_retries = max_retries
        self.timeout = timeout

    def request(self, method: str, url: str, **kwargs) -> Optional[Dict[str, Any]]:
        for attempt in range(self.max_retries):
            try:
                response = requests.request(method, url, timeout=self.timeout, **kwargs)
                response.raise_for_status()
                return response.json()
            except requests.exceptions.RequestException as e:
                if attempt == self.max_retries - 1:
                    print(f"Request failed after {self.max_retries} attempts: {e}")
                    return None
                time.sleep(2 ** attempt)  # Exponential backoff
        return None

    def get(self, url: str, **kwargs) -> Optional[Dict[str, Any]]:
        return self.request('GET', url, **kwargs)

    def post(self, url: str, data: Optional[Dict] = None, **kwargs) -> Optional[Dict[str, Any]]:
        return self.request('POST', url, data=data, **kwargs)

# 示例用法
if __name__ == "__main__":
    client = RetryHTTPClient(max_retries=3, timeout=5.0)
    result = client.get("https://api.example.com/data")
    if result:
        print("Success:", result)
    else:
        print("Request failed.")

