        self.max_connections = max_connections
        self.available_connections = list(range(max_connections))
        self.lock = threading.Lock()

    def borrow_connection(self):
        if self.available_connections:
            conn_id = self.available_connections.pop()
            print(f"Borrowed connection {conn_id}")
            return conn_id
        else:
            print("No connections available")
            return None

    def return_connection(self, conn_id):
        self.available_connections.append(conn_id)
        print(f"Returned connection {conn_id}")

    def simulate_concurrent_access(self):
        def worker():
            conn = self.borrow_connection()
            if conn is not None:
                time.sleep(0.1)  # Simulate work
                self.return_connection(conn)

        threads = []
        for i in range(10):
            t = threading.Thread(target=worker)
            threads.append(t)
            t.start()
        for t in threads:
