import axios from 'axios';

interface ServiceStatus {
  name: string;
  isHealthy: boolean;
  responseTime?: number;
}

async function checkServiceHealth(serviceUrl: string): Promise<ServiceStatus> {
  try {
    const startTime = Date.now();
    const response = await axios.get(serviceUrl);
    const endTime = Date.now();
    const responseTime = endTime - startTime;

    if (response.status === 200) {
      return {
        name: serviceUrl,
        isHealthy: true,
        responseTime: responseTime
      };
    } else {
      return {
        name: serviceUrl,
        isHealthy: false,
        responseTime: responseTime
      };
    }
  } catch (error) {
    console.error(`Error checking service ${serviceUrl}:`, error);
    return {
      name: serviceUrl,
      isHealthy: false
    };
  }
}

async function healthCheckAllServices(serviceUrls: string[]): Promise<ServiceStatus[]> {
  const results: ServiceStatus[] = [];
  for (const url of serviceUrls) {
    const result = await checkServiceHealth(url);
    results.push(result);
  }
  return results;
}

