DECLARE
    file_path TEXT := '/var/log/app/access.log';
    log_line TEXT;
    file_handle TEXT;
    processed_count INT := 0;
BEGIN
    -- 打开日志文件进行读取
    file_handle := pg_read_file(file_path, 0, 1000000);

    -- 逐行处理日志
    FOR log_line IN SELECT unnest(string_to_array(file_handle, E'\n'))
    LOOP
        IF log_line LIKE '%ERROR%' THEN
            INSERT INTO error_logs (log_message, processed_at) VALUES (log_line, NOW());
            processed_count := processed_count + 1;
        END IF;
    END LOOP;

    -- 删除原始日志文件以释放空间
    PERFORM pg_file_unlink(file_path);

    RAISE NOTICE 'Processed % error lines.', processed_count;
EXCEPTION
    WHEN OTHERS THEN
        RAISE NOTICE 'An error occurred: %', SQLERRM;
END;
$$;

