    processed_count INT := 0;
    file_exists BOOLEAN;
BEGIN
    -- 检查文件是否存在
    SELECT EXISTS (SELECT 1 FROM pg_ls_dir('/var/log/app') WHERE pg_ls_dir = split_part(file_path, '/', -1)) INTO file_exists;
    IF NOT file_exists THEN
        RAISE EXCEPTION 'File not found: %', file_path;
    END IF;

    -- 读取文件，处理大小限制
    file_content := pg_read_file(file_path, 0, LEAST(pg_stat_file(file_path).size, max_size));

    -- 逐行处理日志
    FOR log_line IN SELECT unnest(string_to_array(file_content, E'\n'))
    LOOP
        IF log_line LIKE '%ERROR%' THEN
            BEGIN
                INSERT INTO error_logs (log_message, processed_at) VALUES (log_line, NOW());
                processed_count := processed_count + 1;
            EXCEPTION
                WHEN OTHERS THEN
                    RAISE WARNING 'Failed to insert log line: %, Error: %', log_line, SQLERRM;
            END;
        END IF;
    END LOOP;

    -- 仅在成功处理后删除文件
    IF processed_count > 0 THEN
        PERFORM pg_file_unlink(file_path);
        RAISE NOTICE 'Processed % error lines and deleted file.', processed_count;
    ELSE
        RAISE NOTICE 'No error lines found, file retained.';
    END IF;
EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'Procedure failed: %', SQLERRM;
        -- 可添加日志记录或回滚逻辑
END;
$$;
