class CacheManager {
  constructor() {
    this.cache = {};
    this.maxSize = 100;
  }

  set(key, value, ttl = 300000) {
    if (Object.keys(this.cache).length >= this.maxSize) {
      this.evictOldest();
    }
    this.cache[key] = { value, timestamp: Date.now(), ttl };
  }

  get(key) {
    const item = this.cache[key];
    if (!item) return null;
    if (Date.now() - item.timestamp > item.ttl) {
      delete this.cache[key];
      return null;
    }
    return item.value;
  }

  evictOldest() {
    let oldestKey = null;
    let oldestTime = Infinity;
    for (const key in this.cache) {
      if (this.cache[key].timestamp < oldestTime) {
        oldestTime = this.cache[key].timestamp;
        oldestKey = key;
      }
    }
    if (oldestKey) delete this.cache[oldestKey];
  }

  clear() {
    this.cache = {};
  }
}

