CREATE OR REPLACE PROCEDURE process_audio_stream(
    stream_id INT,
    sample_rate INT,
    buffer_size INT
)
LANGUAGE plpgsql
AS $$
DECLARE
    audio_data BYTEA;
    chunk BYTEA;
    total_samples INT := 0;
    processed_samples INT := 0;
    start_time TIMESTAMP;
    end_time TIMESTAMP;
BEGIN
    -- 开始处理音频流
    start_time := CURRENT_TIMESTAMP;

    -- 从流表中读取音频数据
    SELECT audio_content INTO audio_data
    FROM audio_streams
    WHERE id = stream_id;

    IF audio_data IS NULL THEN
        RAISE EXCEPTION 'Audio stream not found for ID: %', stream_id;
    END IF;

    -- 处理音频数据，按缓冲区大小分割
    WHILE processed_samples < LENGTH(audio_data) LOOP
        chunk := SUBSTRING(audio_data FROM processed_samples + 1 FOR buffer_size);

        -- 模拟音频处理，如解码或分析
        PERFORM pg_sleep(0.001);  -- 模拟处理延迟

        -- 更新处理进度
        processed_samples := processed_samples + buffer_size;
        total_samples := total_samples + LENGTH(chunk);

        -- 检查边界条件，防止溢出
        IF processed_samples > LENGTH(audio_data) THEN
            processed_samples := LENGTH(audio_data);
        END IF;

        -- 记录每个块的处理日志
        INSERT INTO audio_processing_log (stream_id, chunk_index, chunk_size, processed_at)
        VALUES (stream_id, processed_samples / buffer_size, LENGTH(chunk), CURRENT_TIMESTAMP);
    END LOOP;

    -- 结束处理
    end_time := CURRENT_TIMESTAMP;

    -- 更新流状态为已处理
    UPDATE audio_streams
    SET status = 'processed',
        processed_at = end_time,
        processing_time = EXTRACT(EPOCH FROM (end_time - start_time))
    WHERE id = stream_id;

    -- 返回处理摘要
    RAISE NOTICE 'Audio stream processed: % samples in % seconds', total_samples, EXTRACT(EPOCH FROM (end_time - start_time));
END;
$$;

