CREATE OR REPLACE PROCEDURE process_audio_stream(
    stream_id INT,
    sample_rate INT,
    buffer_size INT
)
LANGUAGE plpgsql
AS $$
DECLARE
    audio_data BYTEA;
    chunk BYTEA;
    total_samples INT := 0;
    processed_samples INT := 0;
    chunk_index INT := 0;
    start_time TIMESTAMP;
    end_time TIMESTAMP;
