        log_records := log_records || ROW(stream_id, chunk_index, LENGTH(chunk), CURRENT_TIMESTAMP);

        -- 定期批量插入日志以避免过多 I/O
        IF array_length(log_records, 1) >= 100 THEN
            INSERT INTO audio_processing_log (stream_id, chunk_index, chunk_size, processed_at)
            SELECT (r).stream_id, (r).chunk_index, (r).chunk_size, (r).processed_at
            FROM unnest(log_records) AS r;
            log_records := ARRAY[]::RECORD[];  -- 清空数组
        END IF;
    END LOOP;

    -- 插入剩余日志记录
    IF array_length(log_records, 1) > 0 THEN
        INSERT INTO audio_processing_log (stream_id, chunk_index, chunk_size, processed_at)
        SELECT (r).stream_id, (r).chunk_index, (r).chunk_size, (r).processed_at
        FROM unnest(log_records) AS r;
    END IF;

    -- 结束处理
    end_time := CURRENT_TIMESTAMP;

    -- 更新流状态为已处理，使用事务确保一致性
    UPDATE audio_streams
    SET status = 'processed',
        processed_at = end_time,
        processing_time = EXTRACT(EPOCH FROM (end_time - start_time))
    WHERE id = stream_id;

    -- 返回处理摘要
    RAISE NOTICE 'Audio stream processed: % samples in % seconds', total_samples, EXTRACT(EPOCH FROM (end_time - start_time));
END;
$$;
