CREATE OR REPLACE PROCEDURE execute_scheduled_tasks()
LANGUAGE plpgsql
AS $$
DECLARE
    task_id INTEGER;
    task_name VARCHAR(100);
    execution_time TIMESTAMP;
    result VARCHAR(200);
    error_msg TEXT;
    task_cursor CURSOR FOR SELECT id, name, scheduled_time FROM tasks WHERE status = 'pending';
BEGIN
    OPEN task_cursor;
    LOOP
        FETCH task_cursor INTO task_id, task_name, execution_time;
        EXIT WHEN NOT FOUND;

        IF execution_time <= NOW() THEN
            BEGIN
                result := 'Success: Task ' || task_name || ' executed.';
                UPDATE tasks SET status = 'completed', last_executed = NOW() WHERE id = task_id;
                INSERT INTO task_logs (task_id, message, timestamp) VALUES (task_id, result, NOW());
            EXCEPTION
                WHEN OTHERS THEN
                    error_msg := SQLERRM;
                    INSERT INTO task_logs (task_id, message, timestamp) VALUES (task_id, 'Error: ' || error_msg, NOW());
            END;
        END IF;
    END LOOP;
    CLOSE task_cursor;
    COMMIT;
END;
$$;

