import time

class ConnectionPool:
    def __init__(self, max_connections=5):
        self.max_connections = max_connections
        self.available_connections = list(range(max_connections))
        self.lock = threading.Lock()
        self.borrowed_connections = []

    def borrow_connection(self):
        if not self.available_connections:
            raise Exception("No connections available")
        with self.lock:
            conn_id = self.available_connections.pop(0)
            self.borrowed_connections.append(conn_id)
            print(f"Borrowed connection {conn_id}")
            return conn_id

    def return_connection(self, conn_id):
        with self.lock:
            if conn_id in self.borrowed_connections:
                self.borrowed_connections.remove(conn_id)
                self.available_connections.append(conn_id)
                print(f"Returned connection {conn_id}")
            else:
                print(f"Connection {conn_id} not found in borrowed list")

    def simulate_concurrent_borrow(self):
        def worker():
            try:
                conn = self.borrow_connection()
                time.sleep(0.1)  # Simulate work
                self.return_connection(conn)
            except Exception as e:
                print(f"Error: {e}")

        threads = []
        for i in range(10):
            t = threading.Thread(target=worker)
