import re

def analyze_logs(log_file_path):
    """
    分析日志文件，统计每个IP地址的访问次数和总响应时间。
    """
    ip_counts = {}
    ip_response_times = {}

    with open(log_file_path, 'r') as file:
        for line in file:
            # 假设日志格式为：IP地址 - - [时间] "请求" 状态码 响应时间
            match = re.search(r'(\d+\.\d+\.\d+\.\d+) .* (\d+)ms', line)
            if match:
                ip = match.group(1)
                response_time = int(match.group(2))

                # 统计访问次数
                if ip in ip_counts:
                    ip_counts[ip] += 1
                else:
                    ip_counts[ip] = 1

                # 累加响应时间
                if ip in ip_response_times:
                    ip_response_times[ip] += response_time
                else:
                    ip_response_times[ip] = response_time

    # 计算平均响应时间
    results = []
    for ip in ip_counts:
        avg_time = ip_response_times[ip] / ip_counts[ip]
        results.append({
            'ip': ip,
            'count': ip_counts[ip],
            'avg_response_time': avg_time
        })

    # 按访问次数排序
    results.sort(key=lambda x: x['count'], reverse=True)
    return results

