```java
import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.util.HashMap;
import java.util.Map;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class LogAnalyzer {
    private Map<String, Integer> errorCounts;
    private Map<String, Integer> warningCounts;
    private static final Pattern ERROR_PATTERN = Pattern.compile("ERROR\\s*\\[(.*?)\\]");
    private static final Pattern WARNING_PATTERN = Pattern.compile("WARNING\\s*\\[(.*?)\\]");

    public LogAnalyzer() {
        errorCounts = new HashMap<>();
        warningCounts = new HashMap<>();
    }

    public void analyzeLogFile(String filePath) {
        try (BufferedReader br = new BufferedReader(new FileReader(filePath))) {
            String line;
            while ((line = br.readLine()) != null) {
                Matcher errorMatcher = ERROR_PATTERN.matcher(line);
                if (errorMatcher.find()) {
                    String errorType = errorMatcher.group(1).trim();
                    errorCounts.put(errorType, errorCounts.getOrDefault(errorType, 0) + 1);
                } else {
                    Matcher warningMatcher = WARNING_PATTERN.matcher(line);
                    if (warningMatcher.find()) {
                        String warningType = warningMatcher.group(1).trim();
                        warningCounts.put(warningType, warningCounts.getOrDefault(warningType, 0) + 1);
                    }
                }
            }
        } catch (IOException e) {
            System.err.println("Error reading log file: " + e.getMessage());
        }
    }

    public void printStatistics() {
        System.out.println("Error Statistics:");
        for (Map.Entry<String, Integer> entry : errorCounts.entrySet()) {
            System.out.println(entry.getKey() + ": " + entry.getValue());
        }
        System.out.println("Warning Statistics:");
        for (Map.Entry<String, Integer> entry : warningCounts.entrySet()) {
            System.out.println(entry.getKey() + ": " + entry.getValue());
        }
    }

    public static void main(String[] args) {
        LogAnalyzer analyzer = new LogAnalyzer();
        analyzer.analyzeLogFile("application.log");
        analyzer.printStatistics();
    }
}
```

