package main

import (
	"encoding/json"
	"fmt"
	"io/ioutil"
	"os"
	"sync"
)

type DataRecord struct {
	ID    int    `json:"id"`
	Name  string `json:"name"`
	Value string `json:"value"`
}

func convertJSONToCSV(inputFile, outputFile string) error {
	data, err := ioutil.ReadFile(inputFile)
	if err != nil {
		return fmt.Errorf("failed to read input file: %v", err)
	}

	var records []DataRecord
	if err := json.Unmarshal(data, &records); err != nil {
		return fmt.Errorf("failed to unmarshal JSON: %v", err)
	}

	var wg sync.WaitGroup
	csvLines := make([]string, len(records))
	for i, record := range records {
		wg.Add(1)
		go func(idx int, rec DataRecord) {
			defer wg.Done()
			csvLines[idx] = fmt.Sprintf("%d,%s,%s", rec.ID, rec.Name, rec.Value)
		}(i, record)
	}
	wg.Wait()

	outputData := "ID,Name,Value\n"
	for _, line := range csvLines {
		outputData += line + "\n"
	}

	if err := ioutil.WriteFile(outputFile, []byte(outputData), 0644); err != nil {
		return fmt.Errorf("failed to write output file: %v", err)
	}
	return nil
}

func main() {
	if err := convertJSONToCSV("input.json", "output.csv"); err != nil {
		fmt.Printf("Error: %v\n", err)
	}
}

