use tokio::task;
use tokio::sync::mpsc;

async fn process_data(data: String) -> Result<String, String> {
    if data.is_empty() {
        return Err("Empty data".to_string());
    }
    Ok(format!("Processed: {}", data))
}

async fn run_tasks() -> Result<(), String> {
    let data_list = vec!["task1".to_string(), "task2".to_string(), "".to_string()];
    let (tx, mut rx) = mpsc::channel(32);

    for data in data_list {
        let tx_clone = tx.clone();
        task::spawn(async move {
            let result = process_data(data).await;
            if let Err(e) = tx_clone.send(result).await {
                eprintln!("Failed to send result: {}", e);
            }
        });
    }
    drop(tx); // Drop the original sender to allow rx to close

    let mut errors = Vec::new();
    while let Some(result) = rx.recv().await {
        match result {
            Ok(msg) => println!("Success: {}", msg),
            Err(e) => {
                println!("Error: {}", e);
                errors.push(e);
            }
        }
    }

    if !errors.is_empty() {
        return Err(format!("{} tasks failed", errors.len()));
    }
    Ok(())
}

#[tokio::main]
async fn main() {
    if let Err(e) = run_tasks().await {
        eprintln!("Failed: {}", e);
        std::process::exit(1);
    }
}
```

