    constructor() {
        this.resources = new Map();
        this.activeConnections = new Set();
    }

    async acquireResource(resourceId) {
        if (this.resources.has(resourceId)) {
            return this.resources.get(resourceId);
        }
        const resource = await this.createResource(resourceId);
        this.resources.set(resourceId, resource);
        this.activeConnections.add(resourceId);
        return resource;
    }

    async createResource(resourceId) {
        // 模拟异步资源创建，如数据库连接
        await new Promise(resolve => setTimeout(resolve, 100));
        return { id: resourceId, data: `Resource ${resourceId}` };
    }

    releaseResource(resourceId) {
        if (this.activeConnections.has(resourceId)) {
            this.activeConnections.delete(resourceId);
            console.log(`Released resource: ${resourceId}`);
        } else {
            console.warn(`Resource ${resourceId} not found in active connections.`);
        }
        // 可选：清理资源缓存，但可能影响性能
