func processImages(inputDir, outputDir string) error {
    files, err := os.ReadDir(inputDir)
    if err != nil {
        return err
    }

    var wg sync.WaitGroup
    for _, file := range files {
        if filepath.Ext(file.Name()) != ".jpg" {
            continue
        }
        wg.Add(1)
        go func(f os.DirEntry) {
            defer wg.Done()
            inputPath := filepath.Join(inputDir, f.Name())
            outputPath := filepath.Join(outputDir, f.Name())
            imgFile, err := os.Open(inputPath)
            if err != nil {
                fmt.Printf("Error opening %s: %v\n", inputPath, err)
                return
            }
            defer imgFile.Close()
            img, _, err := image.Decode(imgFile)
            if err != nil {
                fmt.Printf("Error decoding %s: %v\n", inputPath, err)
                return
            }
            bounds := img.Bounds()
            newImg := image.NewRGBA(bounds)
            for y := bounds.Min.Y; y < bounds.Max.Y; y++ {
                for x := bounds.Min.X; x < bounds.Max.X; x++ {
                    r, g, b, a := img.At(x, y).RGBA()
                    newImg.Set(x, y, image.RGBA{uint8(r >> 8), uint8(g >> 8), uint8(b >> 8), uint8(a >> 8)})
                }
            }
            outFile, err := os.Create(outputPath)
            if err != nil {
                fmt.Printf("Error creating %s: %v\n", outputPath, err)
                return
            }
            defer outFile.Close()
            if err := jpeg.Encode(outFile, newImg, nil); err != nil {
                fmt.Printf("Error encoding %s: %v\n", outputPath, err)
                return
            }
        }(file)
    }
    wg.Wait()
    return nil
}

