import java.util.HashMap;
import java.util.Map;
import java.util.function.Supplier;

public class RouteDispatcher {
    private Map<String, Supplier<Object>> routes;

    public RouteDispatcher() {
        routes = new HashMap<>();
        // 示例：使用 Supplier 提供类型安全的控制器实例
        routes.put("/home", HomeController::new);
        routes.put("/user", UserController::new);
        routes.put("/admin", AdminController::new);
    }

    public Object dispatch(String path) {
        if (path == null) {
            return new ErrorController();
        }
        Supplier<Object> controllerSupplier = routes.get(path);
        if (controllerSupplier == null) {
            return new NotFoundController();
        }
        return controllerSupplier.get();
    }

    public void addRoute(String path, Supplier<Object> controllerSupplier) {
        if (path != null && controllerSupplier != null) {
            routes.put(path, controllerSupplier);
        }
    }

    public static void main(String[] args) {
        RouteDispatcher dispatcher = new RouteDispatcher();
        System.out.println(dispatcher.dispatch("/home"));
        System.out.println(dispatcher.dispatch("/unknown"));
        dispatcher.addRoute("/test", TestController::new);
        System.out.println(dispatcher.dispatch("/test"));
    }
}

