```javascript
async function sendBatchNotifications(users, message, maxConcurrency = 5) {
  const results = [];
  const promises = [];
  let index = 0;

  async function sendNotification(user) {
    try {
      const response = await fetch('https://api.notification-service.com/send', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ userId: user.id, message: message })
      });
      if (response.ok) {
        results.push({ userId: user.id, status: 'success' });
      } else {
        results.push({ userId: user.id, status: 'failed', error: `HTTP ${response.status}` });
      }
    } catch (error) {
      results.push({ userId: user.id, status: 'failed', error: error.message });
    }
  }

  async function worker() {
    while (index < users.length) {
      const user = users[index];
      index++;
      await sendNotification(user);
    }
  }

  for (let i = 0; i < Math.min(maxConcurrency, users.length); i++) {
    promises.push(worker());
  }
  await Promise.all(promises);
  return results;
}

