  { id: 1, name: 'Alice' },
  { id: 2, name: 'Bob' },
  { id: 3, name: 'Charlie' }
];
sendBatchNotifications(userList, 'New update available!', 3).then(results => {
  console.log('Notification results:', results);
});
```

