use std::collections::HashMap;
use std::sync::{Arc, Mutex};
use std::thread;

struct Message {
    sender_id: u32,
    receiver_id: u32,
    content: String,
}

struct MessageService {
    messages: Arc<Mutex<HashMap<u32, Vec<Message>>>>,
}

impl MessageService {
    fn new() -> Self {
        MessageService {
            messages: Arc::new(Mutex::new(HashMap::new())),
        }
    }

    fn send_message(&self, sender_id: u32, receiver_id: u32, content: String) -> Result<(), String> {
        if sender_id == 0 || receiver_id == 0 {
            return Err("Invalid user ID: IDs must be non-zero".to_string());
        }
        if content.is_empty() || content.len() > 1000 {
            return Err("Content must be non-empty and less than 1000 characters".to_string());
        }

        let message = Message {
            sender_id,
            receiver_id,
            content,
        };
        let mut messages_map = self.messages.lock().unwrap();
        // 预分配向量以避免在锁内分配内存
        messages_map.entry(receiver_id).or_insert_with(|| Vec::with_capacity(10));
        messages_map.get_mut(&receiver_id).unwrap().push(message);
        println!("Message sent from {} to {}: {}", sender_id, receiver_id, content);
        Ok(())
    }

    fn get_messages(&self, user_id: u32) -> Vec<Message> {
        let messages_map = self.messages.lock().unwrap();
        messages_map.get(&user_id).cloned().unwrap_or_default()
    }

    fn clear_messages(&self, user_id: u32) {
        let mut messages_map = self.messages.lock().unwrap();
        messages_map.remove(&user_id);
    }
}

fn main() {
    let service = MessageService::new();
    let service_arc = Arc::new(service);

    let handles: Vec<_> = (0..5).map(|i| {
        let service_clone = Arc::clone(&service_arc);
        thread::spawn(move || {
            for j in 0..10 {
                let sender_id = i + 1; // 确保非零ID
                let receiver_id = ((i + 1) % 5) + 1;
                if let Err(e) = service_clone.send_message(sender_id, receiver_id, format!("Test message {} from thread {}", j, i)) {
                    eprintln!("Failed to send message: {}", e);
                }
            }
        })
    }).collect();

    for handle in handles {
        handle.join().unwrap();
    }

    for i in 1..6 { // 调整ID范围以匹配非零验证
        let messages = service_arc.get_messages(i);
        println!("User {} has {} messages", i, messages.len());
    }
}
```

