  try {
    await cache.setUserData('123', { name: 'Alice', age: 30 });
    const data = await cache.getUserData('123');
    console.log('Retrieved:', data);
  } catch (error) {
    console.error('Operation failed:', error);
  } finally {
    await cache.close(); // 确保连接关闭
