func produceMessages(queueName string, messages []string) error {
    connStr := os.Getenv("RABBITMQ_CONNECTION_STRING")
    if connStr == "" {
        connStr = "amqp://guest:guest@localhost:5672/" // 默认值，仅用于开发
    }
    conn, err := amqp.Dial(connStr)
    if err != nil {
        return fmt.Errorf("failed to connect to RabbitMQ: %v", err)
    }
    defer conn.Close()

    ch, err := conn.Channel()
    if err != nil {
        return fmt.Errorf("failed to open a channel: %v", err)
    }
    defer ch.Close()

    q, err := ch.QueueDeclare(
        queueName,
        false,
        false,
        false,
        false,
        nil,
    )
    if err != nil {
        return fmt.Errorf("failed to declare a queue: %v", err)
    }

    var publishErr error
    for _, msg := range messages {
        err = ch.Publish(
            "",
            q.Name,
            false,
            false,
            amqp.Publishing{
                ContentType: "text/plain",
                Body:        []byte(msg),
            },
        )
        if err != nil {
            log.Printf("Failed to publish message '%s': %v", msg, err)
            if publishErr == nil {
                publishErr = fmt.Errorf("publish failed for message: %s, error: %v", msg, err)
            }
            // 可选：添加重试逻辑或中断循环
        }
        time.Sleep(100 * time.Millisecond)
    }
    return publishErr // 返回第一个发布错误或 nil
}

