use std::collections::HashMap;
use std::fs;
use std::path::Path;
use std::sync::{Arc, Mutex};
use std::thread;

struct Plugin {
    name: String,
    version: String,
    enabled: bool,
}

struct PluginManager {
    plugins: Arc<utex<HashMap<String, Plugin>>>,
}

impl PluginManager {
    fn new() -> Self {
        PluginManager {
            plugins: Arc::new(Mutex::new(HashMap::new())),
        }
    }

    fn load_plugins(&self, plugin_dir: &str) -> Result<(), String> {
        let dir = Path::new(plugin_dir);
        if !dir.is_dir() {
            return Err("Invalid plugin directory".to_string());
        }
        let entries = fs::read_dir(dir).map_err(|e| e.to_string())?;
        for entry in entries {
            let entry = entry.map_err(|e| e.to_string())?;
            let path = entry.path();
            if path.extension().and_then(|ext| ext.to_str()) == Some("so") {
                let name = path.file_stem().unwrap().to_string_lossy().to_string();
                let plugin = Plugin {
                    name: name.clone(),
                    version: "1.0".to_string(),
                    enabled: true,
                };
                let mut plugins = self.plugins.lock().unwrap();
                plugins.insert(name, plugin);
            }
        }
        Ok(())
    }

    fn enable_plugin(&self, name: &str) -> Result<(), String> {
        let mut plugins = self.plugins.lock().unwrap();
        if let Some(plugin) = plugins.get_mut(name) {
            plugin.enabled = true;
            Ok(())
        } else {
            Err("Plugin not found".to_string())
        }
    }

    fn list_plugins(&self) -> Vec<String> {
        let plugins = self.plugins.lock().unwrap();
        plugins.keys().cloned().collect()
    }

    fn concurrent_load(&self, plugin_dir: &str) {
        let manager = Arc::new(self);
        let handle = thread::spawn(move || {
            manager.load_plugins(plugin_dir).unwrap();
        });
        handle.join().unwrap();
    }
}

fn main() {
    let manager = PluginManager::new();
    manager.load_plugins("./plugins").unwrap();
    println!("Plugins loaded: {:?}", manager.list_plugins());
}

