func processWithTimeout(ctx context.Context, data string) (string, error) {
    // 创建一个带超时的子context
    ctx, cancel := context.WithTimeout(ctx, 5*time.Second)
    defer cancel() // 确保资源释放

    // 使用channel来异步处理并支持取消
    resultChan := make(chan string, 1)
    errChan := make(chan error, 1)

    go func() {
        // 模拟耗时操作
        time.Sleep(2 * time.Second)
        select {
        case <-ctx.Done():
            errChan <- ctx.Err()
            return
        default:
            resultChan <- "Processed: " + data
        }
    }()

    // 等待结果或超时/取消
    select {
    case result := <-resultChan:
        return result, nil
    case err := <-errChan:
        return "", err
    case <-ctx.Done():
        return "", ctx.Err()
    }
}

