```javascript
class UserInfoProcessor {
  constructor() {
    this._users = new Map(); // 使用 Map 提高查找效率
  }

  addUser(name, age, email) {
    if (typeof name !== 'string' || name.trim() === '') {
      throw new Error('Name must be a non-empty string');
    }
    if (typeof age !== 'number' || age < 0 || !Number.isInteger(age)) {
      throw new Error('Age must be a non-negative integer');
    }
    if (typeof email !== 'string' || !email.includes('@')) {
      throw new Error('Email must be a valid string with @ symbol');
    }
    if (this._users.has(email)) {
      throw new Error('User with this email already exists');
    }
    this._users.set(email, { name, age, email });
  }

  getUserByEmail(email) {
    return this._users.get(email) || null;
  }

  updateUserAge(email, newAge) {
    if (typeof newAge !== 'number' || newAge < 0 || !Number.isInteger(newAge)) {
      throw new Error('New age must be a non-negative integer');
    }
    const user = this.getUserByEmail(email);
    if (user) {
      user.age = newAge;
    } else {
      throw new Error('User not found');
    }
  }

  getAllUsers() {
    return Array.from(this._users.values()); // 返回副本以保护内部状态
  }

  calculateAverageAge() {
    if (this._users.size === 0) {
      return 0;
    }
    let total = 0;
    for (const user of this._users.values()) {
      total += user.age;
    }
    return total / this._users.size;
  }
}
