import (
    "fmt"
    "sync"
    "time"
)

type TaskScheduler struct {
    tasks      map[string]func()
    mu         sync.Mutex
    running    bool
    stopChan   chan struct{}
}

func NewTaskScheduler() *TaskScheduler {
    return &TaskScheduler{
        tasks:    make(map[string]func()),
        stopChan: make(chan struct{}),
    }
}

func (ts *TaskScheduler) AddTask(name string, task func(), interval time.Duration) {
    ts.mu.Lock()
    defer ts.mu.Unlock()
    ts.tasks[name] = task
    go func() {
        ticker := time.NewTicker(interval)
        defer ticker.Stop()
        for {
            select {
            case <-ticker.C:
                task()
            case <-ts.stopChan:
                return
            }
        }
    }()
}

func (ts *TaskScheduler) Start() {
    ts.mu.Lock()
    defer ts.mu.Unlock()
    if ts.running {
        return
    }
    ts.running = true
}

func (ts *TaskScheduler) Stop() {
    ts.mu.Lock()
    defer ts.mu.Unlock()
    if !ts.running {
        return
    }
    ts.running = false
    close(ts.stopChan)
}

func main() {
    scheduler := NewTaskScheduler()
    scheduler.AddTask("logTask", func() { fmt.Println("Logging at", time.Now()) }, 2*time.Second)
    scheduler.AddTask("cleanupTask", func() { fmt.Println("Cleaning up at", time.Now()) }, 5*time.Second)
    scheduler.Start()
    time.Sleep(10 * time.Second)
    scheduler.Stop()
}

