LANGUAGE plpgsql
AS $$
DECLARE
    service_name VARCHAR(50) := 'payment_service';
    health_status BOOLEAN := FALSE;
    retry_count INTEGER := 0;
    max_retries INTEGER := 5;
    health_check_url VARCHAR(200) := 'http://payment-service:8080/health';
    response_timeout INTEGER := 10; -- 秒
    health_log TABLE (service_name VARCHAR(50), status BOOLEAN, checked_at TIMESTAMP);
