CREATE OR REPLACE PROCEDURE update_user_role(
    p_user_id INT,
    p_new_role VARCHAR(50),
    p_admin_id INT
) AS $$
DECLARE
    v_admin_role VARCHAR(50);
    v_valid_roles VARCHAR[] := ARRAY['user', 'moderator', 'admin']; -- 预定义有效角色列表
BEGIN
    -- 验证新角色是否有效，防止 SQL 注入和无效数据
    IF p_new_role NOT IN (SELECT unnest(v_valid_roles)) THEN
        RAISE EXCEPTION 'Invalid role: %', p_new_role;
    END IF;

    -- 在事务中执行，使用行级锁确保一致性
    BEGIN
        -- 获取管理员角色并锁定行，防止并发修改
        SELECT role INTO v_admin_role
        FROM users
        WHERE user_id = p_admin_id
        FOR UPDATE;

        IF NOT FOUND THEN
            RAISE EXCEPTION 'Admin user not found';
        END IF;

        -- 检查管理员权限
        IF v_admin_role = 'admin' THEN
            -- 更新用户角色，使用参数化查询避免 SQL 注入
            UPDATE users
            SET role = p_new_role
            WHERE user_id = p_user_id
            RETURNING role INTO v_admin_role; -- 可选：确认更新

            IF NOT FOUND THEN
                RAISE EXCEPTION 'User not found';
            END IF;

            -- 记录操作日志
            INSERT INTO audit_log (user_id, action, timestamp, admin_id)
            VALUES (p_user_id, 'role_update', NOW(), p_admin_id);

            RAISE NOTICE 'Role updated successfully for user %', p_user_id;
        ELSE
            RAISE EXCEPTION 'Permission denied: Only admins can update roles';
        END IF;

        COMMIT;
    EXCEPTION
        WHEN OTHERS THEN
            ROLLBACK;
            RAISE EXCEPTION 'An error occurred: %', SQLERRM;
    END;
END;
$$ LANGUAGE plpgsql;
```

### 最佳实践
1. **始终使用参数化查询或输入验证**：在 SQL 中，避免直接拼接用户输入到查询中。使用预定义列表、类型检查或转义函数（如 `quote_ident`）来防止 SQL 注入攻击。
2. **在权限校验中使用事务和锁**：对于涉及权限的并发操作，使用事务（如 `BEGIN`/`COMMIT`）和行级锁（如 `FOR UPDATE`）来确保数据一致性和防止竞态条件，特别是在管理员角色可能被修改的场景中。

