package main

import (
    "fmt"
    "sync"
)

type Event struct {
    Topic   string
    Message string
}

type Subscriber struct {
    ID      int
    Channel chan Event
}

type PubSub struct {
    subscribers map[string][]Subscriber
    mu          sync.RWMutex
}

func NewPubSub() *PubSub {
    return &PubSub{
        subscribers: make(map[string][]Subscriber),
    }
}

func (ps *PubSub) Subscribe(topic string, id int) chan Event {
    ch := make(chan Event, 10)
    ps.mu.Lock()
    defer ps.mu.Unlock()
    ps.subscribers[topic] = append(ps.subscribers[topic], Subscriber{ID: id, Channel: ch})
    return ch
}

func (ps *PubSub) Publish(topic string, message string) {
    ps.mu.RLock()
    defer ps.mu.RUnlock()
    subs, ok := ps.subscribers[topic]
    if !ok {
        return
    }
    for _, sub := range subs {
        go func(s Subscriber) {
            s.Channel <- Event{Topic: topic, Message: message}
        }(sub)
    }
}

func (ps *PubSub) Unsubscribe(topic string, id int) {
    ps.mu.Lock()
    defer ps.mu.Unlock()
    subs, ok := ps.subscribers[topic]
    if !ok {
        return
    }
    for i, sub := range subs {
        if sub.ID == id {
            ps.subscribers[topic] = append(subs[:i], subs[i+1:]...)
            close(sub.Channel)
            break
        }
    }
}

func main() {
    ps := NewPubSub()
    ch1 := ps.Subscribe("news", 1)
    ch2 := ps.Subscribe("news", 2)
    go func() {
        for event := range ch1 {
            fmt.Printf("Subscriber 1: %s - %s\n", event.Topic, event.Message)
        }
    }()
    go func() {
        for event := range ch2 {
            fmt.Printf("Subscriber 2: %s - %s\n", event.Topic, event.Message)
        }
    }()
    ps.Publish("news", "Breaking news!")
    ps.Unsubscribe("news", 1)
    ps.Publish("news", "Another update")
    select {}
}

import time
import hashlib
