from flask import Flask, request, jsonify

app = Flask(__name__)

# 模拟存储的 API tokens，键为 token，值为用户 ID 和过期时间戳
token_store = {
    'abc123': {'user_id': 1, 'expires_at': int(time.time()) + 3600},
    'def456': {'user_id': 2, 'expires_at': int(time.time()) + 7200}
}

def validate_token(token):
    """验证 API token 是否有效"""
    if token in token_store:
        token_data = token_store[token]
        current_time = int(time.time())
        if token_data['expires_at'] > current_time:
            return token_data['user_id']
        else:
            # 过期 token 未从存储中移除
            return None
    return None

def token_middleware(func):
    """API token 校验中间件"""
    def wrapper(*args, **kwargs):
        token = request.headers.get('Authorization')
        if not token:
            return jsonify({'error': 'Missing token'}), 401
        # 移除 'Bearer ' 前缀（如果存在）
        if token.startswith('Bearer '):
            token = token[7:]
        user_id = validate_token(token)
        if user_id is None:
            return jsonify({'error': 'Invalid token'}), 401
        # 将 user_id 添加到请求上下文中
        request.user_id = user_id
        return func(*args, **kwargs)
    return wrapper

@app.route('/api/data', methods=['GET'])
@token_middleware
def get_data():
    """受保护的 API 端点"""
    return jsonify({'data': 'sensitive information', 'user_id': request.user_id})

if __name__ == '__main__':
    app.run(debug=True)

