import json
from typing import Dict, Any, Optional
from pathlib import Path

class ConfigLoader:
    def __init__(self, config_path: str):
        self.config_path = Path(config_path)
        self.config: Optional[Dict[str, Any]] = None

    def load(self) -> Dict[str, Any]:
        """Load and validate configuration from file."""
        if not self.config_path.exists():
            raise FileNotFoundError(f"Config file not found: {self.config_path}")
        if not self.config_path.is_file():
            raise ValueError(f"Path is not a file: {self.config_path}")

        try:
            with open(self.config_path, 'r', encoding='utf-8') as f:
                data = json.load(f)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON in config file: {e}") from e
        except IOError as e:
            raise RuntimeError(f"Error reading config file: {e}") from e

        # Basic validation: ensure required keys exist
        required_keys = {"api_key", "timeout", "retries"}
        if not required_keys.issubset(data.keys()):
            missing = required_keys - data.keys()
            raise ValueError(f"Missing required config keys: {missing}")

        # Type validation for numeric fields
        if not isinstance(data.get("timeout"), (int, float)) or data["timeout"] <= 0:
            raise ValueError("timeout must be a positive number")
        if not isinstance(data.get("retries"), int) or data["retries"] < 0:
            raise ValueError("retries must be a non-negative integer")

        self.config = data
        return self.config

    def get(self, key: str, default: Any = None) -> Any:
        """Safely retrieve a config value with a default."""
        if self.config is None:
            raise RuntimeError("Config not loaded; call load() first")
        return self.config.get(key, default)

