```javascript
// 评分计算接口，用于计算用户对产品的评分
function calculateProductRating(productId, userId) {
    // 使用闭包实现简单缓存，避免重复计算
    const cache = new Map();
    const cacheKey = `${productId}_${userId}`;

    if (cache.has(cacheKey)) {
        return cache.get(cacheKey);
    }

    // 获取用户的所有评分记录
    const userRatings = getUserRatings(userId);

    // 获取产品的所有评分记录
    const productRatings = getProductRatings(productId);

    // 辅助函数计算平均值，处理空数组
    const calculateAverage = (ratings) => {
        if (ratings.length === 0) return 0; // 默认返回0，避免除以零
        const total = ratings.reduce((sum, item) => sum + item.rating, 0);
        return total / ratings.length;
    };

    const userAvg = calculateAverage(userRatings);
    const productAvg = calculateAverage(productRatings);

    // 计算加权评分：用户评分权重0.3，产品评分权重0.7
    const weightedRating = (userAvg * 0.3) + (productAvg * 0.7);

    // 缓存结果
    cache.set(cacheKey, weightedRating);

    // 返回结果
    return weightedRating;
}

// 模拟获取用户评分记录的函数
function getUserRatings(userId) {
    // 模拟数据库查询，返回数组
    return [
        { rating: 4, productId: 1 },
        { rating: 5, productId: 2 },
        { rating: 3, productId: 3 }
    ];
}

// 模拟获取产品评分记录的函数
function getProductRatings(productId) {
    // 模拟数据库查询，返回数组
    return [
        { rating: 4, userId: 1 },
        { rating: 5, userId: 2 },
        { rating: 3, userId: 3 },
        { rating: 2, userId: 4 }
    ];
}
```

### 最佳实践
1. **使用 Map 进行缓存**：`Map` 对象比普通对象更适合作为缓存结构，因为它支持任意类型的键，并且有内置的方法如 `has` 和 `get`，提高代码清晰度和性能。
2. **处理边界条件**：在计算平均值前检查数组长度，避免除以零错误，确保函数在边缘情况下也能稳定运行，例如为新用户或新产品返回默认值。
3. **优化循环和减少重复**：使用 `reduce` 方法替代 `for` 循环来计算总和，这更简洁且易于维护；将重复逻辑提取为辅助函数，提高代码复用性和可读性。

