class DataCache {
  constructor() {
    this.cache = null;
    this.initializing = false;
    this.promise = null;
  }

  async getData() {
    if (this.cache === null) {
      if (!this.initializing) {
        this.initializing = true;
        this.promise = this.fetchData();
        this.cache = await this.promise;
        this.initializing = false;
      } else {
        await this.promise;
      }
    }
    return this.cache;
  }

  async fetchData() {
    // 模拟异步数据获取
    return new Promise(resolve => setTimeout(() => resolve('data'), 100));
  }
}
