use std::sync::{Arc, Mutex};
use std::collections::VecDeque;

struct Connection {
    id: u32,
    active: bool,
}

struct ConnectionPool {
    connections: Arc<Mutex<VecDeque<Connection>>>,
}

impl ConnectionPool {
    fn new() -> Self {
        ConnectionPool {
            connections: Arc::new(Mutex::new(VecDeque::new())),
        }
    }

    fn add_connection(&mut self, conn: Connection) {
        let mut guard = self.connections.lock().unwrap();
        guard.push_back(conn);
    }

    fn get_connection(&self) -> Option<Connection> {
        let mut guard = self.connections.lock().unwrap();
        guard.pop_front()
    }

    fn return_connection(&self, conn: Connection) {
        let mut guard = self.connections.lock().unwrap();
        guard.push_back(conn);
    }

    fn cleanup(&self) {
        let mut guard = self.connections.lock().unwrap();
        guard.retain(|conn| conn.active);
    }
}

fn main() {
    let mut pool = ConnectionPool::new();
    pool.add_connection(Connection { id: 1, active: true });
    pool.add_connection(Connection { id: 2, active: false });

    if let Some(conn) = pool.get_connection() {
        println!("Got connection ID: {}", conn.id);
        pool.return_connection(conn);
    }

    pool.cleanup();
}

