import * as fs from 'fs';
import * as path from 'path';
import * as crypto from 'crypto';

interface BackupConfig {
  sourceDir: string;
  backupDir: string;
  maxBackups: number;
}

class DataBackupScript {
  private config: BackupConfig;

  constructor(config: BackupConfig) {
    this.config = config;
  }

  public async backup(): Promise<void> {
    try {
      const files = fs.readdirSync(this.config.sourceDir);
      const timestamp = Date.now();
      const backupPath = path.join(this.config.backupDir, `backup_${timestamp}`);
      fs.mkdirSync(backupPath, { recursive: true });

      for (const file of files) {
        const sourceFile = path.join(this.config.sourceDir, file);
        const destFile = path.join(backupPath, file);
        fs.copyFileSync(sourceFile, destFile);
      }

      this.cleanupOldBackups();
      console.log(`Backup completed at ${backupPath}`);
    } catch (error) {
      console.error('Backup failed:', error);
    }
  }

  private cleanupOldBackups(): void {
    const backups = fs.readdirSync(this.config.backupDir)
      .filter(item => item.startsWith('backup_'))
      .sort((a, b) => {
        const timeA = parseInt(a.split('_')[1]);
        const timeB = parseInt(b.split('_')[1]);
        return timeB - timeA;
      });

    if (backups.length > this.config.maxBackups) {
      const toDelete = backups.slice(this.config.maxBackups);
      for (const backup of toDelete) {
        const backupPath = path.join(this.config.backupDir, backup);
        fs.rmSync(backupPath, { recursive: true, force: true });
        console.log(`Deleted old backup: ${backupPath}`);
      }
    }
  }

  public async encryptBackup(backupPath: string, password: string): Promise<void> {
    const key = crypto.scryptSync(password, 'salt', 32);
    const cipher = crypto.createCipheriv('aes-256-gcm', key, Buffer.alloc(16, 0));
    const input = fs.createReadStream(backupPath);
    const output = fs.createWriteStream(`${backupPath}.enc`);
    input.pipe(cipher).pipe(output);
    await new Promise((resolve, reject) => {
      output.on('finish', resolve);
      output.on('error', reject);
    });
  }
}

// 示例使用
const config: BackupConfig = {
  sourceDir: '/data/source',
  backupDir: '/data/backups',
  maxBackups: 5
};
const backupScript = new DataBackupScript(config);
backupScript.backup();

