import signal
import sys
import time
import threading
from typing import Optional

class GracefulShutdown:
    def __init__(self, shutdown_timeout: int = 10):
        self.shutdown_timeout = shutdown_timeout
        self.shutdown_event = threading.Event()
        self.threads = []
        self.lock = threading.Lock()

    def register_thread(self, thread: threading.Thread) -> None:
        with self.lock:
            self.threads.append(thread)

    def start(self) -> None:
        signal.signal(signal.SIGINT, self._signal_handler)
        signal.signal(signal.SIGTERM, self._signal_handler)
        print("Service started. Press Ctrl+C to shutdown gracefully.")
        self._wait_for_shutdown()

    def _signal_handler(self, signum, frame) -> None:
        print(f"Received signal {signum}, initiating graceful shutdown...")
        self.shutdown_event.set()

    def _wait_for_shutdown(self) -> None:
        while not self.shutdown_event.is_set():
            time.sleep(0.1)
        self._stop_threads()
        print("Shutdown complete.")

    def _stop_threads(self) -> None:
        with self.lock:
            for thread in self.threads:
                if thread.is_alive():
                    thread.join(timeout=self.shutdown_timeout)
                    if thread.is_alive():
                        print(f"Thread {thread.name} did not stop in time, forcing exit.")

    def run_service(self, target, args=()) -> None:
        thread = threading.Thread(target=target, args=args)
        thread.start()
        self.register_thread(thread)

if __name__ == "__main__":
    def worker():
        while True:
            print("Working...")
            time.sleep(1)

    shutdown_manager = GracefulShutdown(shutdown_timeout=5)
    shutdown_manager.run_service(worker)
    shutdown_manager.start()

