import (
	"fmt"
	"sync"
)

type Connection struct {
	ID int
}

type ConnectionPool struct {
	pool []*Connection
	mu   sync.Mutex
}

func NewConnectionPool(size int) *ConnectionPool {
	cp := &ConnectionPool{
		pool: make([]*Connection, size),
	}
	for i := 0; i < size; i++ {
		cp.pool[i] = &Connection{ID: i}
	}
	return cp
}

func (cp *ConnectionPool) Get() *Connection {
	cp.mu.Lock()
	defer cp.mu.Unlock()
	if len(cp.pool) == 0 {
		return nil
	}
	conn := cp.pool[0]
	cp.pool = cp.pool[1:]
	return conn
}

func (cp *ConnectionPool) Put(conn *Connection) {
	cp.mu.Lock()
	defer cp.mu.Unlock()
	cp.pool = append(cp.pool, conn)
}

func main() {
	pool := NewConnectionPool(5)
	for i := 0; i < 10; i++ {
		conn := pool.Get()
		if conn == nil {
			fmt.Println("No connection available")
			continue
		}
		fmt.Printf("Using connection ID: %d\n", conn.ID)
		pool.Put(conn)
	}
}

