import (
    "fmt"
    "sync"
    "time"
)

type TaskExecutor struct {
    tasks   []func()
    mu      sync.Mutex
    running bool
}

func NewTaskExecutor() *TaskExecutor {
    return &TaskExecutor{
        tasks: make([]func(), 0),
    }
}

func (te *TaskExecutor) AddTask(task func()) {
    te.mu.Lock()
    defer te.mu.Unlock()
    te.tasks = append(te.tasks, task)
}

func (te *TaskExecutor) Start(interval time.Duration) {
    te.mu.Lock()
    if te.running {
        te.mu.Unlock()
        return
    }
    te.running = true
    te.mu.Unlock()

    ticker := time.NewTicker(interval)
    defer ticker.Stop()

    for range ticker.C {
        te.mu.Lock()
        if !te.running {
            te.mu.Unlock()
            break
        }
        tasksCopy := te.tasks
        te.mu.Unlock()

        for _, task := range tasksCopy {
            task()
        }
    }
}

func (te *TaskExecutor) Stop() {
    te.mu.Lock()
    defer te.mu.Unlock()
    te.running = false
}

func main() {
    executor := NewTaskExecutor()
    executor.AddTask(func() {
        fmt.Println("Executing task at", time.Now())
    })
    go executor.Start(2 * time.Second)
    time.Sleep(10 * time.Second)
    executor.Stop()
    fmt.Println("Stopped")
}

import java.io.*;
import java.util.zip.*;

public class ZipProcessor {
    public static void extractZip(String zipFilePath, String destDirPath) {
        try {
            File destDir = new File(destDirPath);
            if (!destDir.exists()) {
                destDir.mkdir();
            }
            FileInputStream fis = new FileInputStream(zipFilePath);
            ZipInputStream zis = new ZipInputStream(fis);
            ZipEntry entry;
            while ((entry = zis.getNextEntry()) != null) {
                File newFile = new File(destDir, entry.getName());
                if (entry.isDirectory()) {
                    newFile.mkdirs();
                    continue;
                }
                FileOutputStream fos = new FileOutputStream(newFile);
                byte[] buffer = new byte[1024];
                int len;
                while ((len = zis.read(buffer)) > 0) {
                    fos.write(buffer, 0, len);
                }
                fos.close();
                zis.closeEntry();
            }
            zis.close();
            fis.close();
        } catch (IOException e) {
            System.out.println("Error: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        extractZip("data.zip", "./output");
    }
}

