type Config struct {
    ServerPort int    `json:"server_port"`
    DatabaseURL string `json:"database_url"`
    LogLevel   string `json:"log_level"`
}

func loadConfig(filePath string) (*Config, error) {
    file, err := os.Open(filePath)
    if err != nil {
        return nil, fmt.Errorf("failed to open config file: %v", err)
    }
    defer file.Close()

    data, err := ioutil.ReadAll(file)
    if err != nil {
        return nil, fmt.Errorf("failed to read config file: %v", err)
    }

    var config Config
    err = json.Unmarshal(data, &config)
    if err != nil {
        return nil, fmt.Errorf("failed to parse config: %v", err)
    }

    // Validate config
    if config.ServerPort <= 0 || config.ServerPort > 65535 {
        return nil, fmt.Errorf("invalid server port: %d", config.ServerPort)
    }
    if config.DatabaseURL == "" {
        return nil, fmt.Errorf("database URL is required")
    }
    if config.LogLevel != "debug" && config.LogLevel != "info" && config.LogLevel != "warn" && config.LogLevel != "error" {
        return nil, fmt.Errorf("invalid log level: %s", config.LogLevel)
    }

    return &config, nil
}

