class Order:
    def __init__(self, order_id, status='pending'):
        self.order_id = order_id
        self.status = status
        self.transitions = {
            'pending': ['processing', 'cancelled'],
            'processing': ['shipped', 'cancelled'],
            'shipped': ['delivered'],
            'delivered': [],
            'cancelled': []
        }

    def change_status(self, new_status):
        if new_status in self.transitions.get(self.status, []):
            self.status = new_status
            return True
        else:
            return False

    def process_order(self):
        if self.status == 'pending':
            self.status = 'processing'
            print(f"Order {self.order_id} is now processing.")
        else:
            print(f"Cannot process order {self.order_id} from status {self.status}.")

    def ship_order(self):
        if self.status == 'processing':
            self.status = 'shipped'
            print(f"Order {self.order_id} has been shipped.")
        else:
            print(f"Cannot ship order {self.order_id} from status {self.status}.")

    def deliver_order(self):
        if self.status == 'shipped':
            self.status = 'delivered'
            print(f"Order {self.order_id} has been delivered.")
        else:
            print(f"Cannot deliver order {self.order_id} from status {self.status}.")

    def cancel_order(self):
        if self.status in ['pending', 'processing']:
            self.status = 'cancelled'
            print(f"Order {self.order_id} has been cancelled.")
        else:
            print(f"Cannot cancel order {self.order_id} from status {self.status}.")

    def get_status(self):
        return self.status

