from contextlib import contextmanager

@contextmanager
def open_file_safely(file_path, mode='r'):
    """上下文管理器，安全地打开文件，确保关闭。"""
    try:
        file = open(file_path, mode)
        yield file
    except FileNotFoundError:
        print(f"文件 {file_path} 未找到。")
        raise
    except PermissionError:
        print(f"无权限访问文件 {file_path}。")
        raise
    finally:
        if 'file' in locals() and not file.closed:
            file.close()

def load_config(config_path):
    """加载配置文件。"""
    with open_file_safely(config_path, 'r') as f:
        config_data = json.load(f)
    return config_data

def process_data(data_file, output_file):
    """处理数据并写入输出文件。"""
    with open_file_safely(data_file, 'r') as infile, open_file_safely(output_file, 'w') as outfile:
        for line in infile:
            processed_line = line.strip().upper()
            outfile.write(processed_line + '\n')

if __name__ == "__main__":
