```typescript
interface Comment {
  id: number;
  content: string;
  author: string;
}

class CommentRenderer {
  private comments: Comment[];
  private nextId: number;

  constructor(comments: Comment[]) {
    this.comments = comments;
    this.nextId = comments.length > 0 ? Math.max(...comments.map(c => c.id)) + 1 : 1;
  }

  public render(): string {
    let html = '<div class="comments">';
    for (let comment of this.comments) {
      const escapedContent = this.escapeHtml(comment.content);
      const escapedAuthor = this.escapeHtml(comment.author);
      html += `<div class="comment">
                <p>${escapedAuthor}: ${escapedContent}</p>
              </div>`;
    }
    html += '</div>';
    return html;
  }

  public addComment(content: string, author: string): void {
    if (!content.trim() || !author.trim()) {
      throw new Error('Content and author cannot be empty');
    }
    const newComment: Comment = {
      id: this.nextId++,
      content: content,
      author: author
    };
    this.comments.push(newComment);
  }

  private escapeHtml(text: string): string {
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
  }
}

// 示例使用
const initialComments: Comment[] = [
  { id: 1, content: 'Great post!', author: 'Alice' },
  { id: 2, content: 'Thanks for sharing.', author: 'Bob' }
];
const renderer = new CommentRenderer(initialComments);
console.log(renderer.render());
try {
  renderer.addComment('<script>alert("XSS")</script>', 'Mallory');
} catch (error) {
  console.error(error.message);
}
console.log(renderer.render());
