public final class ImmutablePerson {
    private final String name;
    private final int age;
    private final List<String> hobbies;

    public ImmutablePerson(String name, int age, List<String> hobbies) {
        if (name == null || name.trim().isEmpty()) {
            throw new IllegalArgumentException("Name cannot be null or empty");
        }
        if (age < 0) {
            throw new IllegalArgumentException("Age must be non-negative");
        }
        if (hobbies == null) {
            throw new IllegalArgumentException("Hobbies cannot be null");
        }
        this.name = name;
        this.age = age;
        this.hobbies = Collections.unmodifiableList(new ArrayList<>(hobbies)); // Defensive copy
    }

    public String getName() {
        return name;
    }

    public int getAge() {
        return age;
    }

    public List<String> getHobbies() {
        return hobbies; // Returns unmodifiable list
    }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (o == null || getClass() != o.getClass()) return false;
        ImmutablePerson that = (ImmutablePerson) o;
        return age == that.age && name.equals(that.name) && hobbies.equals(that.hobbies);
    }

    @Override
    public int hashCode() {
        return Objects.hash(name, age, hobbies);
    }

    @Override
    public String toString() {
        return "ImmutablePerson{name='" + name + "', age=" + age + ", hobbies=" + hobbies + "}";
    }
}

import java.util.ArrayList;
import java.util.List;

public class MathUtils {
    public static double calculateCircleArea(double radius) {
        return 3.14159 * radius * radius;
    }

    public static int factorial(int n) {
        if (n <= 1) return 1;
        int result = 1;
        for (int i = 2; i <= n; i++) {
            result *= i;
        }
        return result;
    }

    public static List<Double> generateFibonacciSequence(int count) {
        List<Double> sequence = new ArrayList<>();
        if (count <= 0) return sequence;
        sequence.add(0.0);
        if (count == 1) return sequence;
        sequence.add(1.0);
        for (int i = 2; i < count; i++) {
            double next = sequence.get(i - 1) + sequence.get(i - 2);
            sequence.add(next);
        }
        return sequence;
    }

    public static double power(double base, int exponent) {
        double result = 1.0;
        for (int i = 0; i < exponent; i++) {
            result *= base;
        }
        return result;
    }

    public static void main(String[] args) {
        System.out.println("Circle area with radius 5: " + calculateCircleArea(5));
        System.out.println("Factorial of 5: " + factorial(5));
        System.out.println("Fibonacci sequence of 10: " + generateFibonacciSequence(10));
        System.out.println("2^3: " + power(2, 3));
    }
}

