import java.util.ArrayList;
import java.util.List;

public class MathUtils {
    public static double calculateCircleArea(double radius) {
        return Math.PI * radius * radius;
    }

    public static long factorial(int n) {
        if (n < 0) throw new IllegalArgumentException("Factorial input must be non-negative");
        if (n <= 1) return 1;
        long result = 1;
        for (int i = 2; i <= n; i++) {
            result *= i;
            if (result < 0) throw new ArithmeticException("Factorial overflow for input: " + n);
        }
        return result;
    }

    public static List<Double> generateFibonacciSequence(int count) {
        List<Double> sequence = new ArrayList<>();
        if (count <= 0) return sequence;
        sequence.add(0.0);
        if (count == 1) return sequence;
        sequence.add(1.0);
        for (int i = 2; i < count; i++) {
            double next = sequence.get(i - 1) + sequence.get(i - 2);
            sequence.add(next);
        }
        return sequence;
    }

    public static double power(double base, int exponent) {
        if (exponent < 0) {
            return 1.0 / power(base, -exponent);
        }
        double result = 1.0;
        for (int i = 0; i < exponent; i++) {
            result *= base;
        }
        return result;
    }

    public static void main(String[] args) {
        System.out.println("Circle area with radius 5: " + calculateCircleArea(5));
        System.out.println("Factorial of 5: " + factorial(5));
        System.out.println("Fibonacci sequence of 10: " + generateFibonacciSequence(10));
        System.out.println("2^3: " + power(2, 3));
        System.out.println("2^(-3): " + power(2, -3));
    }
}
```

