import requests
import time
from typing import Optional, Dict, Any

class RetryableHTTPClient:
    def __init__(self, max_retries: int = 3, timeout: float = 5.0, backoff_factor: float = 1.0):
        self.max_retries = max_retries
        self.timeout = timeout
        self.backoff_factor = backoff_factor

    def request(self, method: str, url: str, **kwargs) -> Optional[Dict[str, Any]]:
        for attempt in range(self.max_retries + 1):
            try:
                response = requests.request(method, url, timeout=self.timeout, **kwargs)
                response.raise_for_status()
                return response.json()
            except requests.exceptions.RequestException as e:
                if attempt == self.max_retries:
                    print(f"Request failed after {self.max_retries} retries: {e}")
                    return None
                wait_time = self.backoff_factor * (2 ** attempt)
                print(f"Attempt {attempt + 1} failed: {e}. Retrying in {wait_time} seconds...")
                time.sleep(wait_time)
        return None

    def get(self, url: str, **kwargs) -> Optional[Dict[str, Any]]:
        return self.request('GET', url, **kwargs)

    def post(self, url: str, data: Optional[Dict] = None, **kwargs) -> Optional[Dict[str, Any]]:
        return self.request('POST', url, data=data, **kwargs)

# 示例用法
if __name__ == "__main__":
    client = RetryableHTTPClient(max_retries=2, timeout=3.0)
    result = client.get("https://api.example.com/data")
    if result:
        print("Success:", result)
    else:
        print("Request failed.")

