            "phone": phone_number,
            "message": message
        }
        response = requests.post(url, data=data)
        if response.status_code == 200:
            print(f"SMS sent to {phone_number}")
        else:
            print(f"Failed to send SMS to {phone_number}")

    def send_verification_code(self, phone_number):
        code = self.generate_code(phone_number)
        message = f"Your verification code is: {code}"
        self.send_sms(phone_number, message)
        # Store code with timestamp for expiration
        self.verification_codes[phone_number] = (code, time.time())

    def verify_code(self, phone_number, user_code):
        if phone_number in self.verification_codes:
            stored_code, timestamp = self.verification_codes[phone_number]
            if time.time() - timestamp > 300:  # 5 minutes expiration
                del self.verification_codes[phone_number]
                return False
            if stored_code == user_code:
                del self.verification_codes[phone_number]
                return True
        return False

