    if err != nil {
        log.Fatal(err)
    }
    fmt.Println(users)
}

CREATE OR REPLACE FUNCTION borrow_connection(pool_name VARCHAR, user_id INT) RETURNS INT AS $$
DECLARE
    conn_id INT;
    max_conns INT := 10;
    current_conns INT;
    available_conns INT;
BEGIN
    -- 检查连接池是否存在
    IF NOT EXISTS (SELECT 1 FROM connection_pools WHERE name = pool_name) THEN
        RAISE EXCEPTION '连接池不存在';
    END IF;

    -- 获取当前连接数
    SELECT COUNT(*) INTO current_conns FROM active_connections WHERE pool = pool_name;

    -- 计算可用连接数
    available_conns := max_conns - current_conns;

    -- 如果没有可用连接，等待
    WHILE available_conns <= 0 LOOP
        PERFORM pg_sleep(0.1);
        SELECT COUNT(*) INTO current_conns FROM active_connections WHERE pool = pool_name;
        available_conns := max_conns - current_conns;
    END LOOP;

    -- 分配连接ID
    SELECT COALESCE(MAX(connection_id), 0) + 1 INTO conn_id FROM active_connections WHERE pool = pool_name;

    -- 插入新连接记录
    INSERT INTO active_connections (pool, connection_id, user_id, borrowed_at) VALUES (pool_name, conn_id, user_id, NOW());

    RETURN conn_id;
EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION '借出连接失败: %', SQLERRM;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION return_connection(pool_name VARCHAR, conn_id INT) RETURNS VOID AS $$
BEGIN
    -- 删除连接记录
    DELETE FROM active_connections WHERE pool = pool_name AND connection_id = conn_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION '连接不存在或已归还';
    END IF;
EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION '归还连接失败: %', SQLERRM;
END;
$$ LANGUAGE plpgsql;

