function findShortestPath(graph, start, end) {
    if (!graph || typeof graph !== 'object') {
        throw new Error('Invalid graph: must be an object representing adjacency list');
    }
    if (!graph.hasOwnProperty(start) || !graph.hasOwnProperty(end)) {
        throw new Error('Start or end node not found in graph');
    }

    let visited = new Set();
    let queue = [];
    let frontIndex = 0; // 使用索引模拟队列，避免 shift 操作
    queue.push({node: start, path: [start]});
    visited.add(start);

    while (frontIndex < queue.length) {
        let currentNode = queue[frontIndex];
        frontIndex++;

        if (currentNode.node === end) {
            return currentNode.path;
        }

        let neighbors = graph[currentNode.node];
        if (!Array.isArray(neighbors)) {
            continue; // 跳过无效邻居列表
        }

        for (let neighbor of neighbors) {
            if (!visited.has(neighbor)) {
                visited.add(neighbor);
                let updatedPath = currentNode.path.slice();
                updatedPath.push(neighbor);
                queue.push({node: neighbor, path: updatedPath});
            }
        }
    }
    return null;
}

