// 最小堆实现用于高效获取前 limit 个元素
class MinHeap {
    constructor(capacity) {
        this.heap = [];
        this.capacity = capacity;
    }

    push(item) {
        if (this.heap.length < this.capacity) {
            this.heap.push(item);
            this._heapifyUp(this.heap.length - 1);
        } else if (item.score > this.heap[0].score) {
            this.heap[0] = item;
            this._heapifyDown(0);
        }
    }

    getSorted() {
        return this.heap.sort((a, b) => b.score - a.score);
    }

    _heapifyUp(index) {
        while (index > 0) {
            const parent = Math.floor((index - 1) / 2);
            if (this.heap[index].score >= this.heap[parent].score) break;
            [this.heap[index], this.heap[parent]] = [this.heap[parent], this.heap[index]];
            index = parent;
        }
    }

    _heapifyDown(index) {
        const length = this.heap.length;
        while (true) {
            let left = 2 * index + 1;
            let right = 2 * index + 2;
            let smallest = index;
            if (left < length && this.heap[left].score < this.heap[smallest].score) smallest = left;
            if (right < length && this.heap[right].score < this.heap[smallest].score) smallest = right;
            if (smallest === index) break;
            [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
            index = smallest;
        }
    }
}

