fn send_http_request(host: &str, port: u16, path: &str) -> Result<String, String> {
    let mut stream = TcpStream::connect(format!("{}:{}", host, port)).map_err(|e| e.to_string())?;
    let request = format!("GET {} HTTP/1.1\r\nHost: {}\r\n\r\n", path, host);
    stream.write_all(request.as_bytes()).map_err(|e| e.to_string())?;

    let mut response = Vec::new();
    stream.read_to_end(&mut response).map_err(|e| e.to_string())?;

    let response_str = str::from_utf8(&response).map_err(|e| e.to_string())?;
    Ok(response_str.to_string())
}

