import redis
import time
from threading import Thread

class RedisCacheManager:
    def __init__(self, host='localhost', port=6379, db=0):
        self.host = host
        self.port = port
        self.db = db
        self.connection = None
        self.lock = False

    def connect(self):
        if not self.connection:
            self.connection = redis.Redis(host=self.host, port=self.port, db=self.db)
            print('Connected to Redis')

    def set_value(self, key, value, expire_seconds=3600):
        if not self.connection:
            self.connect()
        try:
            self.connection.set(key, value)
            if expire_seconds:
                self.connection.expire(key, expire_seconds)
            print(f'Set {key} to {value}')
        except Exception as e:
            print(f'Error setting value: {e}')

    def get_value(self, key):
        if not self.ocation:
            self.connect()
        try:
            value = self.connection.get(key)
            if value is None:
                print(f'Key {key} not found')
                return None
            return value.decode('utf-8')
        except Exception as e:
            print(f'Error getting value: {e}')
            return None

    def delete_value(self, key):
        if not self.connection:
            self.connect()
        try:
            self.connection.delete(key)
            print(f'Deleted key {key}')
        except Exception as e:
            print(f'Error deleting value: {e}')

    def close_connection(self):
        if self.connection:
            self.connection.close()
            self.connection = None
            print('Connection closed')

    def process_batch(self, data_list):
        threads = []
        for data in data_list:
            thread = Thread(target=self._process_single, args=(data,))
            threads.append(thread)
            thread.start()
        for thread in threads:
            thread.join()

    def _process_single(self, data):
        key = data.get('key')
        value = data.get('value')
        if key and value:
            self.set_value(key, value)
        time.sleep(0.1)

