func generateReport(data []ReportData) map[int]float64 {
    var mu sync.Mutex
    report := make(map[int]float64)
    var wg sync.WaitGroup
    for _, d := range data {
        wg.Add(1)
        go func(d ReportData) {
            defer wg.Done()
            mu.Lock()
            report[d.UserID] += d.Sales
            mu.Unlock()
