class ErrorWrapper {
  private errors: Map<string, Error> = new Map();

  addError(key: string, error: Error): void {
    if (!key || typeof key !== 'string') {
      throw new Error('Key must be a non-empty string');
    }
    if (!error || !(error instanceof Error)) {
      throw new Error('Error must be an instance of Error');
    }
    this.errors.set(key, error);
  }

  getError(key: string): Error | undefined {
    return this.errors.get(key);
  }

  getAllErrors(): Map<string, Error> {
    return this.errors;
  }

  clearErrors(): void {
    this.errors.clear();
  }

  wrapErrors(): string {
    let result = '';
    this.errors.forEach((error, key) => {
      result += `Key: ${key}, Message: ${error.message}\n`;
    });
    return result.trim();
  }

  logErrors(): void {
    console.log(this.wrapErrors());
  }
}

