import json
import os
from datetime import datetime

class CacheReader:
    def __init__(self, cache_dir='cache'):
        self.cache_dir = cache_dir
        if not os.path.exists(self.cache_dir):
            os.makedirs(self.cache_dir)

    def read_cache(self, key):
        cache_file = os.path.join(self.cache_dir, f'{key}.json')
        if os.path.exists(cache_file):
            with open(cache_file, 'r') as f:
                data = json.load(f)
                if 'expiry' in data and datetime.now() > datetime.fromisoformat(data['expiry']):
                    os.remove(cache_file)
                    return None
                return data['value']
        else:
            return None

    def update_cache(self, key, value, expiry_minutes=60):
        cache_file = os.path.join(self.cache_dir, f'{key}.json')
        expiry_time = datetime.now().replace(microsecond=0) + datetime.timedelta(minutes=expiry_minutes)
        data = {'value': value, 'expiry': expiry_time.isoformat()}
        with open(cache_file, 'w') as f:
            json.dump(data, f)
        return True

