function middlewareChain(req, res, next) {
    const middlewares = [
        (req, res, next) => {
            console.log('Middleware 1: Logging request');
            req.timestamp = Date.now();
            next();
        },
        (req, res, next) => {
            console.log('Middleware 2: Authentication check');
            if (!req.headers.authorization) {
                res.status(401).send('Unauthorized');
                return;
            }
            next();
        },
        (req, res, next) => {
            console.log('Middleware 3: Data processing');
            req.data = req.body || {};
            next();
        }
    ];

    let index = 0;
    function runNext() {
        if (index < middlewares.length) {
            const middleware = middlewares[index];
            index++;
            middleware(req, res, runNext);
        } else {
            next();
        }
    }
    runNext();
}

