public class ErrorWrapper {
    private String message;
    private int errorCode;
    private Throwable cause;

    public ErrorWrapper(String message, int errorCode, Throwable cause) {
        this.message = message;
        this.errorCode = errorCode;
        this.cause = cause;
    }

    public String getMessage() {
        return message;
    }

    public int getErrorCode() {
        return errorCode;
    }

    public Throwable getCause() {
        return cause;
    }

    public static ErrorWrapper wrapException(Exception e, int code) {
        return new ErrorWrapper(e.getMessage(), code, e);
    }

    public static ErrorWrapper wrapMessage(String msg, int code) {
        return new ErrorWrapper(msg, code, null);
    }

    public String toJson() {
        return String.format("{\"message\": \"%s\", \"errorCode\": %d}", message, errorCode);
    }

    public void logError() {
        System.err.println("Error: " + message + ", Code: " + errorCode);
        if (cause != null) {
            cause.printStackTrace();
        }
    }
}

