class NotificationService {
  private apiKey: string;
  private baseUrl: string = 'https://api.notifications.com';

  constructor(apiKey: string) {
    if (!apiKey || apiKey.trim() === '') {
      throw new Error('API key must be provided and non-empty');
    }
    this.apiKey = apiKey;
  }

  async sendNotification(userId: string, message: string, channel: string): Promise<void> {
    if (!userId || !message || !channel) {
      throw new Error('Invalid input: userId, message, and channel are required');
    }
    if (channel !== 'email' && channel !== 'push' && channel !== 'sms') {
      throw new Error('Invalid channel: must be email, push, or sms');
    }

    const url = `${this.baseUrl}/send`;
    const body = JSON.stringify({
      user_id: userId,
      message: message,
      channel: channel
    });

    try {
      const response = await fetch(url, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${this.apiKey}`
        },
        body: body
      });

      if (!response.ok) {
        throw new Error(`Failed to send notification: ${response.statusText}`);
      }
    } catch (error) {
      console.error('Notification send error:', error);
      throw error; // 重新抛出以便调用者处理
    }
  }

  async sendBulkNotifications(userIds: string[], message: string, channel: string): Promise<void> {
    const promises = userIds.map(userId => this.sendNotification(userId, message, channel));
    await Promise.all(promises);
  }
}

