CREATE OR REPLACE PROCEDURE compress_images_batch(
    IN image_ids INT[],
    IN target_size_kb INT DEFAULT 500,
    IN max_retries INT DEFAULT 3
) AS $$
DECLARE
    img_id INT;
    current_size INT;
    compressed_size INT;
    retry_count INT := 0;
    success_count INT := 0;
    error_messages TEXT[] := ARRAY[]::TEXT[];
BEGIN
    -- 遍历图片ID数组进行压缩
    FOREACH img_id IN ARRAY image_ids LOOP
        retry_count := 0;
        BEGIN
            -- 获取当前图片大小
            SELECT file_size INTO current_size FROM images WHERE id = img_id;
            IF current_size IS NULL THEN
                RAISE NOTICE '图片ID % 不存在，跳过', img_id;
                CONTINUE;
            END IF;

            -- 压缩图片直到达到目标大小或超过重试次数
            WHILE retry_count < max_retries AND current_size > target_size_kb * 1024 LOOP
                -- 模拟压缩操作：更新图片大小
                UPDATE images 
                SET file_size = file_size * 0.8, 
                    compression_ratio = compression_ratio + 0.2,
                    last_compressed = NOW()
                WHERE id = img_id
                RETURNING file_size INTO compressed_size;

                IF compressed_size IS NULL THEN
                    RAISE EXCEPTION '压缩失败，图片ID %', img_id;
                END IF;

                current_size := compressed_size;
                retry_count := retry_count + 1;
            END LOOP;

            -- 检查压缩结果
            IF current_size <= target_size_kb * 1024 THEN
                success_count := success_count + 1;
                RAISE NOTICE '图片ID % 压缩成功，大小: % KB', img_id, current_size / 1024;
            ELSE
                error_messages := array_append(error_messages, FORMAT('图片ID %s 压缩未达标，剩余大小: %s KB', img_id, current_size / 1024));
            END IF;
        EXCEPTION
            WHEN OTHERS THEN
                error_messages := array_append(error_messages, FORMAT('图片ID %s 错误: %s', img_id, SQLERRM));
        END;
    END LOOP;

