package main

import (
    "fmt"
    "sync"
    "time"
)

type DistributedLock struct {
    mu       sync.Mutex
    locked   bool
    lockKey  string
    lockTTL  time.Duration
}

func NewDistributedLock(key string, ttl time.Duration) *DistributedLock {
    return &DistributedLock{
        lockKey: key,
        lockTTL: ttl,
    }
}

func (dl *DistributedLock) Acquire() bool {
    dl.mu.Lock()
    defer dl.mu.Unlock()
    if !dl.locked {
        dl.locked = true
        go func() {
            time.Sleep(dl.lockTTL)
            dl.locked = false
        }()
        return true
    }
    return false
}

func (dl *DistributedLock) Release() {
    dl.mu.Lock()
    defer dl.mu.Unlock()
    dl.locked = false
}

func main() {
    lock := NewDistributedLock("resource1", 5*time.Second)
    var wg sync.WaitGroup
    for i := 0; i < 3; i++ {
        wg.Add(1)
        go func(id int) {
            defer wg.Done()
            if lock.Acquire() {
                fmt.Printf("Goroutine %d acquired lock\n", id)
                time.Sleep(2 * time.Second)
                lock.Release()
                fmt.Printf("Goroutine %d released lock\n", id)
            } else {
                fmt.Printf("Goroutine %d failed to acquire lock\n", id)
            }
        }(i)
    }
    wg.Wait()
}

