use sqlx::{Pool, Postgres, query};
use std::error::Error;

pub struct User {
    id: i32,
    name: String,
    email: String,
}

pub async fn batch_insert_users(
    pool: &Pool<Postgres>,
    users: Vec<User>,
) -> Result<(), Box<dyn Error>> {
    if users.is_empty() {
        return Ok(());
    }

    let mut transaction = pool.begin().await?;

    for user in users {
        let query = "INSERT INTO users (id, name, email) VALUES ($1, $2, $3)";
        sqlx::query(query)
            .bind(user.id)
            .bind(user.name)
            .bind(user.email)
            .execute(&mut *transaction)
            .await?;
    }

    transaction.commit().await?;
    Ok(())
}

