import { Pool, PoolClient, QueryResult } from 'pg';

class DatabaseConnectionManager {
    private static instance: DatabaseConnectionManager;
    private pool: Pool;
    private activeConnections: Map<string, PoolClient>;

    private constructor() {
        this.pool = new Pool({
            host: process.env.DB_HOST || 'localhost',
            port: parseInt(process.env.DB_PORT || '5432'),
            database: process.env.DB_NAME || 'mydb',
            user: process.env.DB_USER || 'postgres',
            password: process.env.DB_PASSWORD || '',
            max: 20,
            idleTimeoutMillis: 30000,
            connectionTimeoutMillis: 2000,
        });
        this.activeConnections = new Map();
        this.pool.on('error', (err) => {
            console.error('Unexpected error on idle client', err);
        });
    }

    public static getInstance(): DatabaseConnectionManager {
        if (!DatabaseConnectionManager.instance) {
            DatabaseConnectionManager.instance = new DatabaseConnectionManager();
        }
        return DatabaseConnectionManager.instance;
    }

    public async getConnection(key: string): Promise<PoolClient> {
        if (this.activeConnections.has(key)) {
            return this.activeConnections.get(key)!;
        }
        const client = await this.pool.connect();
        this.activeConnections.set(key, client);
        return client;
    }

    public async releaseConnection(key: string): Promise<void> {
        const client = this.activeConnections.get(key);
        if (client) {
            client.release();
            this.activeConnections.delete(key);
        }
    }

    public async query<T = any>(sql: string, params?: any[]): Promise<QueryResult<T>> {
        const client = await this.pool.connect();
        try {
            return await client.query(sql, params);
        } finally {
            client.release();
        }
    }

    public async closeAll(): Promise<void> {
        await this.pool.end();
        this.activeConnections.clear();
    }
}

export default DatabaseConnectionManager;

