            throw new IllegalArgumentException("Base64 image cannot be null or empty.");
        }

        byte[] imageBytes = Base64.getDecoder().decode(base64Image);
        if (imageBytes.length > MAX_FILE_SIZE) {
            throw new IllegalArgumentException("File size exceeds the maximum limit of 5MB.");
        }

        // Validate image type
        try (ByteArrayInputStream bais = new ByteArrayInputStream(imageBytes)) {
            BufferedImage image = ImageIO.read(bais);
            if (image == null) {
                throw new IllegalArgumentException("Invalid image format. Only PNG is allowed.");
            }
        }

        String fileName = userId + "_" + UUID.randomUUID().toString() + ".png";
        Path uploadDirPath = Paths.get(UPLOAD_DIR);
        Files.createDirectories(uploadDirPath); // Atomic directory creation

        Path outputPath = uploadDirPath.resolve(fileName);
        // Check for existing file to handle UUID collisions
        int counter = 1;
        while (Files.exists(outputPath)) {
            fileName = userId + "_" + UUID.randomUUID().toString() + "_" + counter + ".png";
            outputPath = uploadDirPath.resolve(fileName);
            counter++;
        }

        Files.write(outputPath, imageBytes);

        // Use a logger instead of System.out
        // Logger.getLogger(AvatarUploadService.class.getName()).info("Uploaded avatar for user " + userId);

        return fileName;
    }

    public void deleteAvatar(String fileName) throws IOException {
        if (!FILE_NAME_PATTERN.matcher(fileName).matches()) {
            throw new IllegalArgumentException("Invalid file name.");
        }
        Path filePath = Paths.get(UPLOAD_DIR).resolve(fileName).normalize();
        if (!filePath.startsWith(Paths.get(UPLOAD_DIR).normalize())) {
            throw new SecurityException("Path traversal attempt detected.");
        }
        if (Files.exists(filePath)) {
            Files.delete(filePath);
        }
