use std::collections::HashMap;
use std::sync::{Arc, Mutex};
use std::thread;

struct Order {
    id: u32,
    status: String,
    amount: f64,
}

struct OrderManager {
    orders: Arc<Mutex<HashMap<u32, Order>>>,
}

impl OrderManager {
    fn new() -> Self {
        OrderManager {
            orders: Arc::new(Mutex::new(HashMap::new())),
        }
    }

    fn update_order_status(&self, order_id: u32, new_status: String) -> Result<(), String> {
        let mut orders = self.orders.lock().unwrap();
        if let Some(order) = orders.get_mut(&order_id) {
            order.status = new_status;
            Ok(())
        } else {
            Err(format!("Order {} not found", order_id))
        }
    }

    fn process_orders_concurrently(&self, updates: Vec<(u32, String)>) {
        let handles: Vec<_> = updates
            .into_iter()
            .map(|(order_id, status)| {
                let manager = Arc::clone(&self.orders);
                thread::spawn(move || {
                    let mut orders = manager.lock().unwrap();
                    if let Some(order) = orders.get_mut(&order_id) {
                        order.status = status;
                    }
                })
            })
            .collect();
        for handle in handles {
            handle.join().unwrap();
        }
    }

    fn get_order_status(&self, order_id: u32) -> Option<String> {
        let orders = self.orders.lock().unwrap();
        orders.get(&order_id).map(|order| order.status.clone())
    }
}

fn main() {
    let manager = OrderManager::new();
    let mut orders_map = manager.orders.lock().unwrap();
    orders_map.insert(1, Order { id: 1, status: "pending".to_string(), amount: 100.0 });
    orders_map.insert(2, Order { id: 2, status: "shipped".to_string(), amount: 200.0 });
    drop(orders_map);

    let updates = vec![(1, "completed".to_string()), (2, "delivered".to_string())];
    manager.process_orders_concurrently(updates);

    println!("Order 1 status: {:?}", manager.get_order_status(1));
    println!("Order 2 status: {:?}", manager.get_order_status(2));
}

