```go
package main

import "fmt"

type OrderStatus int

const (
    Pending OrderStatus = iota
    Processing
    Shipped
    Delivered
    Cancelled
)

type Order struct {
    status OrderStatus
}

func (o *Order) updateStatus(newStatus OrderStatus) bool {
    // 定义状态转换规则
    switch o.status {
    case Pending:
        if newStatus == Processing || newStatus == Cancelled {
            o.status = newStatus
            return true
        }
    case Processing:
        if newStatus == Shipped || newStatus == Cancelled {
            o.status = newStatus
            return true
        }
    case Shipped:
        if newStatus == Delivered || newStatus == Cancelled {
            o.status = newStatus
            return true
        }
    case Delivered, Cancelled:
        // 最终状态不允许再转换
        return false
    }
    return false
}

func (o *Order) printStatus() {
    switch o.status {
    case Pending:
        fmt.Println("订单待处理")
    case Processing:
        fmt.Println("订单处理中")
    case Shipped:
        fmt.Println("订单已发货")
    case Delivered:
        fmt.Println("订单已送达")
    case Cancelled:
        fmt.Println("订单已取消")
    default:
        fmt.Println("未知状态")
    }
}

func main() {
    order := Order{status: Pending}
    order.printStatus()
    if order.updateStatus(Processing) {
        order.printStatus()
    } else {
        fmt.Println("状态转换失败")
    }
    if order.updateStatus(Delivered) {
        order.printStatus()
    } else {
        fmt.Println("状态转换失败")
    }
}
```

