import (
    "context"
    "fmt"
    "time"
)

func processWithTimeout(ctx context.Context, data string) (string, error) {
    // 创建一个带超时的子context
    ctx, cancel := context.WithTimeout(ctx, 5*time.Second)
    defer cancel() // 确保取消函数被调用，避免资源泄漏

    // 使用一个channel来模拟异步处理
    resultChan := make(chan string, 1)
    errChan := make(chan error, 1)

    go func() {
        // 模拟耗时操作
        time.Sleep(3 * time.Second)
        select {
        case <-ctx.Done():
            errChan <- ctx.Err() // 如果context被取消或超时，返回错误
            return
        default:
            resultChan <- "Processed: " + data
        }
    }()

    select {
    case result := <-resultChan:
        return result, nil
    case err := <-errChan:
        return "", err
    case <-ctx.Done():
        return "", ctx.Err() // 处理超时或取消
    }
}

func main() {
    ctx := context.Background()
    result, err := processWithTimeout(ctx, "test data")
    if err != nil {
        fmt.Printf("Error: %v\n", err)
        return
    }
    fmt.Println(result)
}

