package main

import (
    "fmt"
    "io"
    "net/http"
    "os"
    "path/filepath"
)

func uploadHandler(w http.ResponseWriter, r *http.Request) {
    if r.Method != "POST" {
        http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
        return
    }

    file, header, err := r.FormFile("file")
    if err != nil {
        http.Error(w, "Failed to get file", http.StatusBadRequest)
        return
    }
    defer file.Close()

    // 保存文件到服务器
    filename := header.Filename
    filePath := filepath.Join("./uploads", filename)
    dst, err := os.Create(filePath)
    if err != nil {
        http.Error(w, "Failed to create file", http.StatusInternalServerError)
        return
    }
    defer dst.Close()

    if _, err := io.Copy(dst, file); err != nil {
        http.Error(w, "Failed to save file", http.StatusInternalServerError)
        return
    }

    fmt.Fprintf(w, "File uploaded successfully: %s", filename)
}

func main() {
    http.HandleFunc("/upload", uploadHandler)
    http.ListenAndServe(":8080", nil)
}

import java.util.ArrayList;
import java.util.List;

public class ScoreCalculator {
    private List<Double> scores;

    public ScoreCalculator() {
        scores = new ArrayList<>();
    }

    public void addScore(double score) {
        scores.add(score);
    }

    public double calculateAverage() {
        double sum = 0.0;
        for (int i = 0; i < scores.size(); i++) {
            sum += scores.get(i);
        }
        return sum / scores.size();
    }

    public double calculateWeightedAverage(List<Double> weights) {
        if (weights.size() != scores.size()) {
            throw new IllegalArgumentException("Weights size must match scores size");
        }
        double weightedSum = 0.0;
        double totalWeight = 0.0;
        for (int i = 0; i < scores.size(); i++) {
            weightedSum += scores.get(i) * weights.get(i);
            totalWeight += weights.get(i);
        }
        return weightedSum / totalWeight;
    }

    public List<Double> getTopScores(int n) {
        List<Double> sortedScores = new ArrayList<>(scores);
        sortedScores.sort((a, b) -> Double.compare(b, a));
        return sortedScores.subList(0, Math.min(n, sortedScores.size()));
    }
}

