import java.util.ArrayList;
import java.util.List;
import java.util.PriorityQueue;

public class ScoreCalculator {
    private List<Double> scores;

    public ScoreCalculator() {
        scores = new ArrayList<>();
    }

    public void addScore(double score) {
        scores.add(score);
    }

    public double calculateAverage() {
        double sum = 0.0;
        int size = scores.size();
        for (int i = 0; i < size; i++) {
            sum += scores.get(i);
        }
        return sum / size;
    }

    public double calculateWeightedAverage(List<Double> weights) {
        if (weights.size() != scores.size()) {
            throw new IllegalArgumentException("Weights size must match scores size");
        }
        double weightedSum = 0.0;
        double totalWeight = 0.0;
        int size = scores.size();
        for (int i = 0; i < size; i++) {
            weightedSum += scores.get(i) * weights.get(i);
            totalWeight += weights.get(i);
        }
        return weightedSum / totalWeight;
    }

    public List<Double> getTopScores(int n) {
        if (n <= 0) {
            return new ArrayList<>();
        }
        PriorityQueue<Double> minHeap = new PriorityQueue<>(n);
        for (double score : scores) {
            if (minHeap.size() < n) {
                minHeap.offer(score);
            } else if (score > minHeap.peek()) {
                minHeap.poll();
                minHeap.offer(score);
            }
        }
        List<Double> topScores = new ArrayList<>(minHeap);
        topScores.sort((a, b) -> Double.compare(b, a)); // 降序排序
        return topScores;
    }
}
```

