                raise ValueError("Value too high")
            print(f"Processed: {data}")
            return True
        except json.JSONDecodeError as e:
            print(f"JSON decode error: {e}")
            return False
        except Exception as e:
            print(f"Unexpected error: {e}")
            return False

    def _consume_messages(self):
        retry_count = 0
        while self.running:
