import threading
import time
from datetime import datetime

class TaskScheduler:
    def __init__(self):
        self.tasks = []
        self.lock = threading.Lock()
        self.running = False
        self.thread = None

    def add_task(self, task_func, interval_seconds):
        with self.lock:
            self.tasks.append({
                'func': task_func,
                'interval': interval_seconds,
                'last_run': 0
            })

    def start(self):
        if self.running:
            return
        self.running = True
        self.thread = threading.Thread(target=self._run_scheduler)
        self.thread.start()

    def stop(self):
        self.running = False
        if self.thread:
            self.thread.join()

    def _run_scheduler(self):
        while self.running:
            current_time = time.time()
            with self.lock:
                for task in self.tasks:
                    if current_time - task['last_run'] >= task['interval']:
                        task['last_run'] = current_time
                        threading.Thread(target=task['func']).start()
            time.sleep(0.1)

# 示例使用
