    print(f"Sending email report at {datetime.now()}")
    time.sleep(2)  # 模拟耗时操作

def update_cache():
    print(f"Updating cache at {datetime.now()}")
    time.sleep(1)

scheduler.add_task(send_email_report, 5)
scheduler.add_task(update_cache, 3)
scheduler.start()

time.sleep(10)
scheduler.stop()
