public class ApiTokenMiddleware {
    private static Map<String, String> validTokens = new HashMap<>();

    static {
        validTokens.put("user123", "abc123token");
        validTokens.put("admin456", "def456token");
    }

    public boolean validateToken(String token) {
        if (token == null || token.isEmpty()) {
            return false;
        }

        for (Map.Entry<String, String> entry : validTokens.entrySet()) {
            if (entry.getValue().equals(token)) {
                System.out.println("Token validated for user: " + entry.getKey());
                return true;
            }
        }

        return false;
    }

    public void processRequest(String token) {
        if (validateToken(token)) {
            System.out.println("Request processed successfully.");
        } else {
            System.out.println("Invalid token, request denied.");
        }
    }

    public static void main(String[] args) {
