import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.HashMap;
import java.util.Map;

public class ApiTokenMiddleware {
    private static Map<String, String> validTokenHashes = new HashMap<>();

    static {
        // 从环境变量或安全存储加载 token 哈希值，示例中使用哈希值
        validTokenHashes.put("user123", hashToken("abc123token"));
        validTokenHashes.put("admin456", hashToken("def456token"));
    }

    private static String hashToken(String token) {
        try {
            MessageDigest md = MessageDigest.getInstance("SHA-256");
            byte[] hash = md.digest(token.getBytes());
            return bytesToHex(hash);
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException("Hashing algorithm not available", e);
        }
    }

    private static String bytesToHex(byte[] bytes) {
        StringBuilder hexString = new StringBuilder();
        for (byte b : bytes) {
            String hex = Integer.toHexString(0xff & b);
            if (hex.length() == 1) hexString.append('0');
            hexString.append(hex);
        }
        return hexString.toString();
    }

    public boolean validateToken(String token) {
        if (token == null || token.isEmpty()) {
            return false;
        }

        String tokenHash = hashToken(token);
        for (Map.Entry<String, String> entry : validTokenHashes.entrySet()) {
            if (constantTimeEquals(entry.getValue(), tokenHash)) {
                System.out.println("Token validated successfully.");
                return true;
            }
        }

        return false;
    }

    private boolean constantTimeEquals(String a, String b) {
        if (a.length() != b.length()) {
            return false;
        }
        int result = 0;
        for (int i = 0; i < a.length(); i++) {
            result |= a.charAt(i) ^ b.charAt(i);
        }
        return result == 0;
    }

    public void processRequest(String token) {
        if (validateToken(token)) {
            System.out.println("Request processed successfully.");
        } else {
            System.out.println("Invalid token, request denied.");
        }
    }

    public static void main(String[] args) {
        ApiTokenMiddleware middleware = new ApiTokenMiddleware();
        middleware.processRequest("abc123token");
        middleware.processRequest("invalidToken");
    }
}
