import * as fs from 'fs';
import * as path from 'path';

type ReportData = {
  id: number;
  name: string;
  amount: number;
  date: string;
};

class ReportExporter {
  private data: ReportData[];
  private outputDir: string;

  constructor(data: ReportData[], outputDir: string) {
    this.data = data;
    // 验证和规范化输出目录，防止路径遍历
    this.outputDir = path.resolve(outputDir);
    if (!this.outputDir.startsWith(process.cwd())) {
      throw new Error('Output directory must be within current working directory.');
    }
  }

  async exportToCSV(fileSuffix?: string): Promise<void> {
    if (!this.data || this.data.length === 0) {
      console.log('No data to export.');
      return;
    }

    // 使用 UUID 和可选后缀生成唯一文件名，避免并发冲突
    const { v4: uuidv4 } = require('uuid');
    const fileName = `report_${uuidv4()}${fileSuffix ? '_' + fileSuffix : ''}.csv`;
    const filePath = path.join(this.outputDir, fileName);

    // 清理数据字段，防止 CSV 注入
    const escapeCsv = (value: string): string => {
      if (value.includes(',') || value.includes('\n') || value.includes('"')) {
        return `"${value.replace(/"/g, '""')}"`;
      }
      return value;
    };

    let csvContent = 'ID,Name,Amount,Date\n';
    for (const item of this.data) {
      csvContent += `${item.id},${escapeCsv(item.name)},${item.amount},${escapeCsv(item.date)}\n`;
    }

    // 确保输出目录存在
    await fs.promises.mkdir(this.outputDir, { recursive: true });

    try {
      await fs.promises.writeFile(filePath, csvContent, { encoding: 'utf8' });
      console.log(`Report exported to ${filePath}`);
    } catch (error) {
      console.error('Failed to export report:', error);
    }
  }

  async exportMultipleReports(reports: ReportData[][]): Promise<void> {
    const promises = reports.map((reportData, index) => {
      const exporter = new ReportExporter(reportData, this.outputDir);
      // 为每个报告添加索引后缀，确保文件名唯一
      return exporter.exportToCSV(`batch_${index}`);
    });
    await Promise.all(promises);
    console.log('All reports exported.');
  }
}

