CREATE OR REPLACE PROCEDURE process_async_tasks()
LANGUAGE plpgsql
AS $$
DECLARE
    task_id INTEGER;
    task_status VARCHAR(20) := 'pending';
    retry_count INTEGER := 0;
    max_retries CONSTANT INTEGER := 3;
    task_record RECORD;
    result_text TEXT;
BEGIN
    -- 获取所有待处理任务
    FOR task_record IN SELECT id, data FROM async_tasks WHERE status = 'pending' ORDER BY created_at ASC
    LOOP
        task_id := task_record.id;
        -- 模拟异步处理，这里用简单延迟代替
        PERFORM pg_sleep(0.1);
        -- 尝试执行任务
        BEGIN
            result_text := 'Processed: ' || task_record.data;
            UPDATE async_tasks SET status = 'completed', result = result_text WHERE id = task_id;
        EXCEPTION WHEN OTHERS THEN
            retry_count := retry_count + 1;
            IF retry_count < max_retries THEN
                UPDATE async_tasks SET status = 'retrying', retry_count = retry_count WHERE id = task_id;
                CONTINUE;
            ELSE
                UPDATE async_tasks SET status = 'failed', error = SQLERRM WHERE id = task_id;
            END IF;
        END;
        -- 重置重试计数为下一个任务
        retry_count := 0;
    END LOOP;
    -- 清理已完成的任务（假设保留7天）
    DELETE FROM async_tasks WHERE status = 'completed' AND created_at < NOW() - INTERVAL '7 days';
END;
$$;

