import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.SQLException;
import java.util.concurrent.atomic.AtomicInteger;

public class DatabaseConnectionManager {
    private static final String URL = "jdbc:mysql://localhost:3306/mydb";
    private static final String USER = "root";
    private static final String PASSWORD = "password";
    private static final int MAX_CONNECTIONS = 10;
    private static final AtomicInteger activeConnections = new AtomicInteger(0);
    private static final Connection[] connectionPool = new Connection[MAX_CONNECTIONS];

    static {
        try {
            Class.forName("com.mysql.cj.jdbc.Driver");
            for (int i = 0; i < MAX_CONNECTIONS; i++) {
                connectionPool[i] = DriverManager.getConnection(URL, USER, PASSWORD);
            }
        } catch (ClassNotFoundException | SQLException e) {
            e.printStackTrace();
        }
    }

    public static synchronized Connection getConnection() {
        if (activeConnections.get() >= MAX_CONNECTIONS) {
            throw new IllegalStateException("No available connections in pool");
        }
        for (int i = 0; i < MAX_CONNECTIONS; i++) {
            try {
                if (connectionPool[i] != null && !connectionPool[i].isClosed()) {
                    activeConnections.incrementAndGet();
                    return connectionPool[i];
                }
            } catch (SQLException e) {
                e.printStackTrace();
            }
        }
        throw new IllegalStateException("Failed to get a connection");
    }

    public static synchronized void releaseConnection(Connection conn) {
        if (conn != null) {
            activeConnections.decrementAndGet();
        }
    }
}

