import fs from 'fs';
import path from 'path';
import { exec } from 'child_process';

interface BackupConfig {
    sourceDir: string;
    backupDir: string;
    maxBackups: number;
}

class BackupScript {
    private config: BackupConfig;
    private backupQueue: string[] = [];

    constructor(config: BackupConfig) {
        this.config = config;
    }

    public async backup(): Promise<void> {
        const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
        const backupName = `backup-${timestamp}.tar.gz`;
        const backupPath = path.join(this.config.backupDir, backupName);
        const sourcePath = this.config.sourceDir;

        // 使用 tar 命令压缩备份
        const command = `tar -czf ${backupPath} -C ${sourcePath} .`;
        exec(command, (error, stdout, stderr) => {
            if (error) {
                console.error(`Backup failed: ${error.message}`);
                return;
            }
            console.log(`Backup created: ${backupPath}`);
            this.cleanupOldBackups();
        });

        this.backupQueue.push(backupPath);
    }

    private cleanupOldBackups(): void {
        fs.readdir(this.config.backupDir, (err, files) => {
            if (err) {
                console.error(`Failed to list backups: ${err.message}`);
                return;
            }

            const backupFiles = files.filter(file => file.startsWith('backup-') && file.endsWith('.tar.gz'));
            backupFiles.sort();

            if (backupFiles.length > this.config.maxBackups) {
                const filesToDelete = backupFiles.slice(0, backupFiles.length - this.config.maxBackups);
                filesToDelete.forEach(file => {
                    const filePath = path.join(this.config.backupDir, file);
                    fs.unlink(filePath, unlinkErr => {
                        if (unlinkErr) {
                            console.error(`Failed to delete old backup ${file}: ${unlinkErr.message}`);
                        } else {
                            console.log(`Deleted old backup: ${file}`);
                        }
                    });
                });
            }
        });
    }

    public getBackupQueue(): string[] {
        return this.backupQueue;
    }
}

