use std::collections::HashMap;
use std::sync::{Arc, Mutex};
use std::time::{Duration, SystemTime};
use rand::{thread_rng, Rng};
use rand::distributions::Alphanumeric;

struct SmsService {
    verification_codes: Arc<Mutex<HashMap<String, (String, SystemTime)>>>,
}

impl SmsService {
    pub fn new() -> Self {
        SmsService {
            verification_codes: Arc::new(Mutex::new(HashMap::new())),
        }
    }

    pub fn generate_and_send_code(&self, phone_number: &str) -> Result<(), String> {
        let code = self.generate_code();
        // 模拟发送短信，实际中应集成短信API并处理错误
        println!("Sending SMS to {} with code: {}", phone_number, code);
        let mut codes = self.verification_codes.lock().map_err(|e| e.to_string())?;
        let expiry = SystemTime::now() + Duration::from_secs(300); // 5分钟过期
        codes.insert(phone_number.to_string(), (code, expiry));
        Ok(())
    }

    fn generate_code(&self) -> String {
        let mut rng = thread_rng();
        // 生成8位字母数字混合验证码，提高强度
        (0..8).map(|_| rng.sample(Alphanumeric) as char).collect()
    }

    pub fn verify_code(&self, phone_number: &str, input_code: &str) -> bool {
        let mut codes = self.verification_codes.lock().unwrap();
        if let Some((stored_code, expiry)) = codes.get(phone_number) {
            if SystemTime::now() <= *expiry && stored_code == input_code {
                codes.remove(phone_number); // 验证成功后移除
                return true;
            }
        }
        false
    }
}

fn main() {
    let service = SmsService::new();
    if let Err(e) = service.generate_and_send_code("+1234567890") {
        eprintln!("Failed to send code: {}", e);
    }
    let is_valid = service.verify_code("+1234567890", "A1b2C3d4");
    println!("Verification result: {}", is_valid);
}
```

### 最佳实践
1. 使用强随机验证码：避免纯数字，采用字母数字混合且足够长度（如8位），以减少暴力破解风险。
2. 实现验证码过期机制：存储验证码时添加时间戳，并在验证时检查是否过期，防止重放攻击。
3. 完善错误处理：在锁操作和外部服务调用（如短信发送）中使用 `Result` 和错误传播，避免使用 `unwrap()` 导致崩溃。

