import java.io.FileOutputStream;
import java.io.IOException;
import java.nio.file.Paths;
import java.util.Scanner;
import com.google.zxing.BarcodeFormat;
import com.google.zxing.WriterException;
import com.google.zxing.client.j2se.MatrixToImageWriter;
import com.google.zxing.common.BitMatrix;
import com.google.zxing.qrcode.QRCodeWriter;

public class QRCodeGenerator {
    public static void generateQRCode(String data, String filePath) throws WriterException, IOException {
        if (data == null || data.isEmpty()) {
            throw new IllegalArgumentException("Data cannot be null or empty");
        }
        if (filePath == null || filePath.isEmpty() || filePath.contains("..")) {
            throw new IllegalArgumentException("Invalid file path");
        }
        if (data.length() > 1000) {
            throw new IllegalArgumentException("Data too long for QR code");
        }
        QRCodeWriter qrCodeWriter = new QRCodeWriter();
        BitMatrix bitMatrix = qrCodeWriter.encode(data, BarcodeFormat.QR_CODE, 300, 300);
        try (FileOutputStream fos = new FileOutputStream(Paths.get(filePath).toFile())) {
            MatrixToImageWriter.writeToStream(bitMatrix, "PNG", fos);
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter data to encode in QR code: ");
        String data = scanner.nextLine();
        System.out.print("Enter output file path: ");
        String filePath = scanner.nextLine();
