```sql
CREATE OR REPLACE FUNCTION fetch_http_data(url TEXT, method TEXT DEFAULT 'GET', headers JSONB DEFAULT '{}'::JSONB, body TEXT DEFAULT NULL)
RETURNS TABLE(status_code INT, response_body TEXT) AS $$
DECLARE
    http_result RECORD;
    valid_methods TEXT[] := ARRAY['GET', 'POST', 'PUT', 'DELETE', 'PATCH'];
BEGIN
    -- Validate method parameter
    IF method NOT IN (SELECT unnest(valid_methods)) THEN
        RAISE EXCEPTION 'Invalid HTTP method: %', method;
    END IF;

    -- Perform HTTP request with error handling
    BEGIN
        SELECT * INTO http_result
        FROM http(
            (SELECT jsonb_build_object('method', method, 'url', url, 'headers', headers, 'body', body))
        );
    EXCEPTION
        WHEN OTHERS THEN
            RAISE EXCEPTION 'HTTP request failed: %', SQLERRM;
    END;

    -- Return status and body
    status_code := http_result.status;
    response_body := http_result.content;
    RETURN NEXT;
END;
$$ LANGUAGE plpgsql;
