import threading

class EventBus:
    def __init__(self):
        self.listeners = []
        self.lock = threading.Lock()

    def subscribe(self, listener):
        with self.lock:
            self.listeners.append(listener)

    def publish(self, event):
        for listener in self.listeners:
            listener(event)

    def unsubscribe(self, listener):
        with self.lock:
            self.listeners.remove(listener)

