CREATE OR REPLACE PROCEDURE process_queue_messages()
LANGUAGE plpgsql
AS $$
DECLARE
    message_record RECORD;
    queue_name TEXT := 'user_notifications';
    max_retries INTEGER := 3;
    retry_count INTEGER := 0;
    error_message TEXT;
BEGIN
    -- 从消息队列中获取消息
    FOR message_record IN SELECT * FROM message_queue WHERE queue = queue_name AND processed = FALSE LIMIT 10 LOOP
        retry_count := 0;
        BEGIN
            -- 模拟处理消息：发送通知
            INSERT INTO notifications (user_id, message, sent_at) 
            VALUES (message_record.user_id, message_record.content, NOW());

            -- 标记消息为已处理
            UPDATE message_queue SET processed = TRUE WHERE id = message_record.id;

            -- 记录处理日志
            INSERT INTO processing_log (message_id, status, timestamp) 
            VALUES (message_record.id, 'SUCCESS', NOW());
        EXCEPTION
            WHEN OTHERS THEN
                error_message := SQLERRM;
                -- 重试逻辑
                WHILE retry_count < max_retries LOOP
                    retry_count := retry_count + 1;
                    BEGIN
                        INSERT INTO notifications (user_id, message, sent_at) 
                        VALUES (message_record.user_id, message_record.content, NOW());
                        UPDATE message_queue SET processed = TRUE WHERE id = message_record.id;
                        INSERT INTO processing_log (message_id, status, timestamp) 
                        VALUES (message_record.id, 'SUCCESS', NOW());
                        EXIT;
                    EXCEPTION
                        WHEN OTHERS THEN
                            IF retry_count = max_retries THEN
                                INSERT INTO processing_log (message_id, status, error_message, timestamp) 
                                VALUES (message_record.id, 'FAILED', error_message, NOW());
                            END IF;
                    END;
                END LOOP;
        END;
    END LOOP;
END;
